INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-01', 'Core domain: Study, Treatment, Stratum, CaseCell → SuccessRate falls out', 'complete', 'Studies, Treatments, Strata, CaseCells', 'For each (stratum, treatment) cell in a study, what is the success rate?', 'Kidney stone study (Charig 1986): 2 strata (small/large), 2 treatments (A/B), 4 cells. CellSuccessRate is the first derived fact.', 'Ask: for each treatment, what is its pooled (across all strata) success rate? That requires TreatmentSummary — aggregating CaseCells by treatment, ignoring stratum.', 'tradition-historical', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-02', 'TreatmentSummary: pooled rate per treatment across all strata', 'complete', 'TreatmentSummaries', 'If you ignore stratum entirely, what is each treatment''s overall success rate?', 'Pooled: A=273/350=78%, B=289/350=83%. B looks better — this is the misleading aggregate view.', 'Ask: for each (stratum, treatment) pair, what is the success rate WITHIN that stratum? That requires StratumSummary — the view that contradicts the pooled view.', 'tradition-historical', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-03', 'StratumSummary: per-stratum rate per treatment — the true picture', 'complete', 'StratumSummaries', 'Within each stratum, which treatment has the higher success rate?', 'Small: A=93.1% > B=86.7%. Large: A=73.0% > B=68.8%. A wins in BOTH strata. Contradiction with pooled view is now visible.', 'Ask: for each treatment pair in a study, does the pooled winner match the per-stratum winner? That requires TreatmentRanking — the node where the paradox either exists or doesn''t.', 'tradition-historical', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-04', 'TreatmentRanking: does the pooled winner = the per-stratum winner?', 'complete', 'TreatmentRankings', 'When pooled and stratified conclusions disagree — which treatment should actually be preferred?', 'Pooled winner = B. Per-stratum winner = A in every stratum. Simpson''s Paradox: IsReversal = true. This is the paradox as a derived fact, not a modeled entity.', 'Ask: WHY does the paradox occur? The stratifying variable (stone size) affects both treatment assignment AND outcome. Name it as a StratumVariable with a CausalRole field.', 'tradition-historical', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-05', 'StratumVariable: name the confounding factor, its causal role, and derive IsConfounder + IsParadoxExplained', 'complete', 'StratumVariables (one per study); CausalRole field; IsConfounder boolean; IsParadoxExplained on TreatmentRankings', 'What IS the stratum variable, why does it confound, and does the model witness its own explanation?', 'kidney-1986: VariableName=stone_size, CausalRole=confounder, AffectsTreatmentAssignment=true, AffectsOutcome=true → IsConfounder=true → IsParadoxExplained=true on TreatmentRankings.', 'Ask: how large is the allocation imbalance? Derive TreatmentExposureFraction on CaseCells — the fraction of each treatment''s cases that land in each stratum. High imbalance = confounding mechanism as a witnessed number.', 'tradition-dag', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-06', 'TreatmentExposureFraction: the allocation imbalance as a witnessed number', 'complete', 'TreatmentExposureFraction field on CaseCells (Cases / TotalCasesForTreatment in this study)', 'What fraction of each treatment''s total cases fall in each stratum? High imbalance across strata is the mechanism of confounding.', 'A: 263/350=75% in large-stone stratum. B: 80/350=23% in large-stone stratum. The 52-point gap IS the mechanism — now a first-class derived number.', 'Add a degenerate study where treatment allocation is perfectly balanced across strata. IsReversal must be FALSE — not because the data says so, but because the algebra guarantees it. The model witnesses its own structural impossibility.', 'tradition-epidemiology', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-07', 'Degenerate study: balanced allocation → IsReversal structurally impossible', 'complete', 'Second Studies row (balanced-synthetic); equal TreatmentExposureFraction across strata; IsReversal = FALSE by construction', 'If every stratum gets the same treatment-allocation fraction, can a reversal occur? The DAG should witness that it cannot.', 'Synthetic: A and B each assigned 50/50 to small/large strata. A=60% success both strata, B=50% both. Pooled: A=60%, B=50%. No reversal. IsParadoxExplained vacuously true (IsConfounder=false, no confounding, no reversal).', 'Add Berkeley 1973 — same DAG, contested domain. Aggregate: women admitted at lower rate. Per-department: women admitted at equal or higher rate in most. IsReversal=true. But IsConfounder is ambiguous — department choice may be downstream of gender (mediator, not confounder). The model witnesses its own explanatory limits.', 'tradition-historical', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-08', 'Berkeley 1973: contested confounder — model reveals a PARTIAL paradox, not a clean reversal', 'complete', 'Third Studies row (berkeley-1973); StratumVariable=department; CausalRole=contested; IsConfounder=false; IsParadoxExplained=false; PerStratumWinner=none (mixed, not unanimous)', 'Does Berkeley show a clean reversal? No — PerStratumWinner=''none'' because the per-stratum winner is mixed (female wins 3/4 depts, male wins 1). The model surfaces a structural limit of the reversal definition: partial paradoxes are real but don''t satisfy the strict IsReversal criterion.', 'Witnessed: male pooled 52.8% vs female 39.9% (large gap). Per dept: female wins A (82%>62%), B (68%>63%), D (35%>33%); male wins C (37%>34%). No unanimous per-stratum winner → IsReversal=FALSE by strict definition. The intuitive paradox is real; the formal paradox is partial.', 'Add ParadoxStrength (scalar severity) to capture partial reversals — pooled gap and average per-stratum gap regardless of unanimity. Then StudySummary for epistemic coverage across all 3 studies.', 'tradition-epidemiology', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-09', 'ParadoxStrength: scalar severity derived from pooled gap and per-stratum gap', 'complete', 'ParadoxStrength on TreatmentRankings; PooledGap and AvgStratumGap on StratumSummaries', 'How large is the reversal? Can we rank studies by paradox severity, and does strength correlate with allocation imbalance?', 'Kidney: pooled gap ~4.6pp favoring B, avg stratum gap ~5pp favoring A. Berkeley: larger pooled gap, varies by department. Balanced: strength=0 (no reversal).', 'StudySummary: roll up ReversalCount, ExplainedCount, AvgParadoxStrength across all studies. The model now describes its own epistemic coverage in a single view.', 'tradition-historical', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-10', 'StudySummary: the model witnesses its own epistemic coverage', 'complete', 'StudySummary table (one row per model instance): StudyCount, ReversalCount, ExplainedCount, UnexplainedCount, ImpossibleCount, AvgParadoxStrength', 'Across all studies in this model, what is the epistemic state? How many reversals, how many explained, how many witnessed-but-unexplained?', '3 studies: ReversalCount=2 (kidney+berkeley), ExplainedCount=1 (kidney), UnexplainedCount=1 (berkeley), ImpossibleCount=1 (balanced). The model now holds a mirror to itself.', 'Ask: how heavy is each stratum? Add StratumFraction to StratumSummaries — the fraction of the study''s total cases that land in each stratum. The weight each stratum carries IS the lever the confounder pulls.', 'tradition-historical', 'b96e0fe6e3402d85b16e9772518d9241c64c1b1e', '2026-06-27', 'loop-05: StratumVariables + IsParadoxExplained — the DAG witnesses its own explanation', 'sp-loop-milestone-01-loops-01-10') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-11', 'StratumFraction: the weight each stratum carries in the pooled average', 'complete', 'StratumFraction (and StudyTotalCases, StratumTotalCases) on StratumSummaries', 'What fraction of the study''s total cases land in each stratum? High StratumFraction on a low-success stratum pulls the pooled rate down — and when that stratum is also over-allocated to one treatment, the reversal follows.', 'kidney-1986: large-stratum = (263+80)/700 = 49%; small-stratum = (87+270)/700 = 51%. Nearly equal stratum weights — but unequal per-treatment allocation (75% of A is in large; 23% of B is in large). The weight alone is not the mechanism; the differential allocation into heavy strata is.', 'Add WeightedStratumRate: StratumFraction × StratumSuccessRate per treatment row. Sum these across strata to reconstruct PooledRate from first principles. The DAG now witnesses the mechanism equation: pooled rate = weighted average of stratum rates.', 'tradition-epidemiology', '49f01e7cafcdb6b529db5743081ee7b32d708b01', '2026-06-27', 'loop-15: ReversalThreshold — intensity and margin witness paradox robustness vs fragility', 'sp-loop-milestone-03-loops-11-15') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-12', 'WeightedPull: mechanism equation witnessed — pooled rate = weighted sum of stratum rates', 'complete', 'WeightedStratumRate on StratumSummaries; PooledRateFromWeightsA and PooledRateFromWeightsB on TreatmentRankings', 'Can the DAG reconstruct each treatment''s pooled rate purely from stratum weights × stratum rates? If PooledRateFromWeights = PooledRate, the mechanism equation is verified: Simpson''s Paradox is algebraically explained.', 'kidney-1986: PooledRateFromWeightsA=0.833, PooledRateFromWeightsB=0.779 (A looks better under equal study-level weights). But actual pooled rates are A=0.780, B=0.826 (B looks better). The divergence IS the mechanism: real pooled uses treatment-level allocation weights; the reconstruction uses study-level weights. The swap between the two orderings shows exactly how differential allocation flips the conclusion. balanced-synthetic: weights match exactly (equal allocation = no flip possible).', 'Add AllocationBias to StratumSummaries: the difference between TreatmentExposureFraction for A and B in each stratum. High bias toward the losing treatment in a low-success stratum IS the confounder''s fingerprint as a witnessed number.', 'tradition-historical', '49f01e7cafcdb6b529db5743081ee7b32d708b01', '2026-06-27', 'loop-15: ReversalThreshold — intensity and margin witness paradox robustness vs fragility', 'sp-loop-milestone-03-loops-11-15') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-13', 'AllocationBias: the confounder''s fingerprint as a signed witnessed number', 'complete', 'AllocationBias on StratumSummaries (AllocationFractionA - AllocationFractionB); also AllocationFractionA, AllocationFractionB, TreatmentACasesHere, TreatmentBCasesHere, TreatmentATotalCases, TreatmentBTotalCases', 'In each stratum, is one treatment disproportionately concentrated here? AllocationBias = AllocationFractionA - AllocationFractionB: positive means A is over-represented here, negative means B is. A strong negative bias in a low-success stratum is the confounder''s fingerprint.', 'kidney-1986 large-stratum: AllocationFractionA=263/350=0.751, AllocationFractionB=80/350=0.229, AllocationBias=+0.523. A is massively over-allocated to the hard (large-stone) stratum. This single number summarizes why the pooled rate misleads: A carries 52pp more exposure to the hard case, dragging its pooled average down below B''s despite beating B in both strata.', 'Add a 4th study: kidney-balanced — same stratum rates as kidney-1986 but with equal allocation (50/50 split). AllocationBias=0 everywhere, IsReversal=FALSE. The counterfactual shows the reversal is purely an allocation artifact, not a property of the treatment rates themselves.', 'tradition-historical', '49f01e7cafcdb6b529db5743081ee7b32d708b01', '2026-06-27', 'loop-15: ReversalThreshold — intensity and margin witness paradox robustness vs fragility', 'sp-loop-milestone-03-loops-11-15') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-14', 'Counterfactual: kidney-balanced isolates allocation as the sole cause of the reversal', 'complete', 'Fourth study (kidney-balanced): same stratum rates as kidney-1986, equal allocation (175 cases per cell). IsReversal=FALSE, AllocationBias=0, ParadoxStrength=0.', 'If the same doctors, same disease, same treatments, same stratum difficulty — but patients were allocated equally — would the paradox still exist? The DAG answers: no. The reversal lives in the allocation, not in the treatment rates.', 'kidney-balanced: PooledRateA = (163+128)/350 = 0.831, PooledRateB = (152+120)/350 = 0.777. A wins pooled AND per-stratum. IsReversal=FALSE, ParadoxStrength=0. AllocationBias=0 in both strata. The counterfactual witnesses that the reversal in kidney-1986 is entirely an artifact of differential allocation, not of treatment efficacy.', 'Add ReversalThreshold to TreatmentRankings: the minimum AllocationBias magnitude needed to flip the pooled winner. How far is kidney-1986 from the threshold? How close is berkeley-1973? This quantifies paradox fragility vs robustness.', 'tradition-historical', '49f01e7cafcdb6b529db5743081ee7b32d708b01', '2026-06-27', 'loop-15: ReversalThreshold — intensity and margin witness paradox robustness vs fragility', 'sp-loop-milestone-03-loops-11-15') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-15', 'ReversalThreshold: how robust or fragile is each study''s paradox?', 'complete', 'MaxAllocationBias, WeightedStratumGapSum, ThresholdMargin on TreatmentRankings', 'How much allocation bias is needed to produce a reversal? Is the observed bias well above threshold (robust paradox) or barely over it (fragile paradox)? ThresholdMargin = observed bias minus minimum needed.', 'kidney-1986: ReversalIntensity=1.0, ThresholdMargin=+0.5 — maximally robust, every stratum opposes pooled. berkeley-1973: ReversalIntensity=0.75, ThresholdMargin=+0.25 — past threshold but not unanimous (3/4 departments oppose). balanced-synthetic and kidney-balanced: intensity=0, margin=-0.5 — structurally impossible. ThresholdMargin > 0 means the paradox is robust; < 0 means absent or impossible.', 'Pour a real-world dataset with a known mediator (not confounder) through the same DAG and witness where it lands on the reversal_intensity × paradox_strength plane. The geometry of the plane is the next frontier.', 'tradition-historical', '49f01e7cafcdb6b529db5743081ee7b32d708b01', '2026-06-27', 'loop-15: ReversalThreshold — intensity and margin witness paradox robustness vs fragility', 'sp-loop-milestone-03-loops-11-15') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-16', 'StratumGap: per-stratum rate difference as a signed witnessed number', 'complete', 'StratumGap field on StratumSummaries (StratumRateA - StratumRateB, signed)', 'In each stratum, how large is the treatment advantage, and in which direction? StratumGap > 0 means A wins here; < 0 means B wins. Summing StratumGap × StratumFraction gives the equal-weight pooled gap — a new derived node.', 'kidney-1986: small-stratum gap = +0.064 (A wins by 6.4pp), large-stratum gap = +0.043 (A wins by 4.3pp). Both positive — A wins everywhere. The pooled gap is negative (B appears to win by 4.6pp) purely due to allocation. The signed gap makes this contradiction arithmetically visible in one column. kidney-balanced: small=+0.064, large=+0.042 (same signs, same magnitudes — the rates are identical to kidney-1986 but now A also wins pooled because allocation is balanced). balanced-synthetic: small=+0.10, large=+0.10 (constant, equal allocation). berkeley-1973: dept-A=−0.200 (female wins), dept-B=+0.011 (male wins barely), dept-C=−0.002 (female wins barely), dept-D=−0.016 (female wins). Mixed signs confirm the partial paradox: no unanimous StratumGap direction, hence no clean reversal.', 'Derive WeightedStratumGapSum on TreatmentRankings: SUM(StratumGap × StratumFraction) aggregated across all TreatmentA rows for this study. This is the equal-weight pooled gap — the gap allocation-free weighting would produce. When WeightedStratumGapSum and PooledGap have opposite signs, the allocation has not just compressed the signal but flipped it. That sign flip is a more precise characterisation of Simpson''s Paradox than IsReversal: it handles partial flips and gives a magnitude to the distortion.', 'tradition-historical', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-17', 'WeightedStratumGapSum: the equal-weight signal — and the Berkeley category error witnessed', 'complete', 'WeightedStratumGap on StratumSummaries (StratumGap × StratumFraction, the per-stratum contribution to the equal-weight pooled gap); WeightedStratumGapSum on TreatmentRankings (SUMIFS of WeightedStratumGap across TreatmentA rows); SignedPooledGap (PooledRateA − PooledRateB, signed); IsSignFlip boolean (WeightedStratumGapSum and SignedPooledGap have opposite signs)', 'If allocation were equal across strata, what would the pooled gap be? WeightedStratumGapSum answers this. When it has the opposite sign to SignedPooledGap, the allocation has not just compressed the signal — it has flipped it. That sign flip IS Simpson''s Paradox under a continuous definition. Does Berkeley sign-flip?', 'Witnessed from DB: balanced-synthetic: WSGSUM=+0.1000, SignedPooledGap=+0.1000 → IsSignFlip=FALSE (equal allocation, no distortion). kidney-1986: WSGSUM=+0.0537, SignedPooledGap=−0.0457 → IsSignFlip=TRUE (A wins in every stratum by 5.4pp on average, but actual pooled shows B winning by 4.6pp). kidney-balanced: WSGSUM=+0.0543, SignedPooledGap=+0.0543 → IsSignFlip=FALSE (equal allocation, WSGSUM = actual pooled gap). berkeley-1973: WSGSUM=−0.0642, SignedPooledGap=+0.1292 → IsSignFlip=TRUE. Per-stratum breakdown: dept-A gap=−0.2035 (female wins by 20.4pp, fraction=0.289); dept-B=−0.0496 (female wins, fraction=0.181); dept-C=+0.0286 (male wins barely, fraction=0.284); dept-D=−0.0184 (female wins, fraction=0.245). Under equal allocation female would win pooled by 6.4pp — but the actual pooled shows male winning by 12.9pp. Berkeley IS a Simpson''s Paradox under the sign-flip definition despite IsReversal=FALSE. The binary unanimity criterion excluded Berkeley because dept-C goes to male; the sign-flip criterion correctly includes it.', 'The sign flip is witnessed. Now measure the magnitude: how far has the allocation bent the pooled signal? AllocationDistortion = |WeightedStratumGapSum − SignedPooledGap|. Berkeley: |−0.0642 − (+0.1292)| = 0.1934. Kidney: |+0.0537 − (−0.0457)| = 0.0994. Berkeley''s distortion is nearly twice kidney''s — despite IsReversal=FALSE. This is the single-number measure that ranks studies by how badly confounding has distorted their pooled result.', 'tradition-historical', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-18', 'AllocationDistortion: the magnitude of the signal the allocation erased or fabricated', 'complete', 'AllocationDistortion on TreatmentRankings (|WeightedStratumGapSum − SignedPooledGap|) — the scalar distance between the equal-weight signal and the actual pooled signal', 'How much has the allocation distorted the pooled signal relative to what equal-weight strata would show? AllocationDistortion=0 means the allocation is neutral. A large AllocationDistortion means the pooled number is mostly noise from case assignment, not signal about treatment efficacy.', 'Witnessed from DB (ordered by AllocationDistortion desc): berkeley-1973: WSGSUM=−0.0642, SignedPooledGap=+0.1292, AllocationDistortion=0.1934. kidney-1986: WSGSUM=+0.0537, SignedPooledGap=−0.0457, AllocationDistortion=0.0994. kidney-balanced: AllocationDistortion=0.0000 (balanced allocation, no distortion). balanced-synthetic: AllocationDistortion=0.0000 (equal allocation, no distortion). The allocation is injecting a 19.3pp distortion into Berkeley''s pooled result — reversing a real female advantage of 6.4pp into an apparent male advantage of 12.9pp. This is nearly twice the 9.9pp distortion in kidney-1986. ParadoxStrength (old measure) gives berkeley=0.0969, kidney=0.0457 — same ordinal ranking but ParadoxStrength is penalized by the unanimity criterion: Berkeley''s 0.75 ReversalIntensity reduces its score. AllocationDistortion is not so penalized: it measures what the allocation DID to the signal, not whether the outcome passes an arbitrary threshold.', 'Two severity measures are now live: ParadoxStrength and AllocationDistortion. They agree on ordinal ranking across our four studies but diverge in magnitude (Berkeley is 2× kidney under AllocationDistortion but only 2.1× under ParadoxStrength). The more important question: is a study with AllocationDistortion > 0 but IsSignFlip=FALSE possible? That would be a type-C study — allocation has compressed but not reversed the signal. None of the current studies are type-C. Design a synthetic type-C study: same-sign WSGSUM and SignedPooledGap, but WSGSUM closer to zero than SignedPooledGap. Add it to the data and witness AllocationDistortion > 0, IsSignFlip=FALSE.', 'tradition-historical', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-19', 'Type-C witness: compressed-synthetic — allocation distortion without sign flip', 'complete', 'compressed-synthetic study (fifth study): type-C case — A wins every stratum and wins pooled, but allocation compresses A''s pooled advantage. Witnesses AllocationDistortion > 0, IsSignFlip=FALSE, IsReversal=FALSE, PerStratumWinner=A. Completes the four-type taxonomy.', 'Does a study with real allocation distortion (AllocationDistortion > 0) but no sign flip (IsSignFlip=FALSE) exist? If yes, the type-C cell in the DistortionType taxonomy is nonempty — there is a class of misleading aggregates that compress but do not reverse the pooled signal. This class is invisible to both IsReversal and IsSignFlip but is visible to AllocationDistortion.', 'Witnessed from DB (ordered by AllocationDistortion desc): berkeley-1973: WSGSUM=−0.0642, SignedPooledGap=+0.1292, IsSignFlip=TRUE, AllocationDistortion=0.1934, ReversalIntensity=0.75 → type B. kidney-1986: WSGSUM=+0.0537, SignedPooledGap=−0.0457, IsSignFlip=TRUE, AllocationDistortion=0.0994, ReversalIntensity=1.0 → type A. compressed-synthetic: WSGSUM=+0.1000, SignedPooledGap=+0.0600, IsSignFlip=FALSE, AllocationDistortion=0.0400, ReversalIntensity=0.0 → type C (A wins pooled by 6pp but would win by 10pp under equal allocation). kidney-balanced: AllocationDistortion=0.0000 → type D. balanced-synthetic: AllocationDistortion=0.0000 → type D. All four types are now empirically populated. Type-C is important: a researcher seeing pooled A=78%, B=72% and concluding ''A wins by 6pp'' is correct — but the equal-weight truth is ''A wins by 10pp.'' The allocation has consumed 4pp of signal without a single stratum switching winner.', 'All four DistortionType cells are now populated. Add DistortionType as a derived field on TreatmentRankings: A = IsSignFlip AND ReversalIntensity=1.0; B = IsSignFlip AND ReversalIntensity<1.0; C = NOT IsSignFlip AND AllocationDistortion>0.01; D = AllocationDistortion≤0.01. This makes the geometric taxonomy a first-class derived fact in the DAG. Then add PolicyImplication per type: type A = stratify-immediately; type B = investigate-confounder; type C = check-allocation-bias; type D = pooled-analysis-trustworthy.', 'tradition-historical', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-20', 'Hydration contract: real study data enters through 05b-customize-data.sql, not the rulebook JSON', 'complete', 'Real study data lives directly in the rulebook JSON — the SSoT is unified. Provenance files in data/raw/. The view chain computes everything from there.', 'Can real published study data enter the instrument through a SQL hydration file (not the rulebook JSON) and produce DistortionType / AllocationDistortion / PolicyImplication results from the existing view chain without any schema changes?', 'Two real studies hydrated: reintjes-2000 (Epidemiology 2000, N=3519, antibiotic prophylaxis UTI study) and radelet-1981 (Am Soc Rev 1981, N=326, Florida death penalty). Both are type-A full reversals. Witnessed: reintjes AllocationDistortion=0.0516, radelet AllocationDistortion=0.0684. No schema changes were needed. 05b-customize-data.sql is the durable hydration path.', 'ModelSummary currently counts only synthetic studies in its ReversalCount/NonReversalCount. Add DistortionType aggregations (TypeACount, TypeBCount, TypeCCount, TypeDCount, SignFlipCount, AvgAllocationDistortion) so the model''s self-portrait reflects all seven studies including the two real ones.', 'tradition-epidemiology', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-20b', 'Two real studies witnessed: reintjes-2000 and radelet-1981 — both type-A full reversals from real data in the rulebook', 'complete', 'Two non-canonical published datasets poured through the hydration contract. Provenance files in data/raw/. Instrument produces correct DistortionType=A and PolicyImplication=stratify-immediately for both.', 'Do two real published studies with well-known outcomes (antibiotic prophylaxis UTI reversal; racial death-penalty reversal) produce the expected DistortionType=A when hydrated through the instrument? Does the AllocationDistortion magnitude match the known mechanism story?', 'Witnessed from DB (full table ordered by AllocationDistortion desc): berkeley-1973: type B, distortion=0.1934. kidney-1986: type A, distortion=0.0994. radelet-1981: type A, distortion=0.0684 (REAL). reintjes-2000: type A, distortion=0.0516 (REAL). compressed-synthetic: type C, distortion=0.0400. kidney-balanced: type D, distortion=0.0000. balanced-synthetic: type D, distortion=0.0000. Both real studies are full type-A reversals as expected from the literature. radelet has higher AllocationDistortion (0.0684) than reintjes (0.0516), consistent with the victim-race confound being stronger — black defendants are 62% in the low-sentence black-victim stratum, a more extreme allocation imbalance than reintjes where 87% of prophylaxis patients are in low-incidence hospitals.', 'ModelSummary currently counts only the synthetic study set. Add DistortionType aggregations (TypeACount, TypeBCount, TypeCCount, TypeDCount, SignFlipCount, AvgAllocationDistortion) so the model describes its real empirical coverage, not just the synthetic controls.', 'tradition-epidemiology', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-21', 'DistortionType + PolicyImplication: the four-type taxonomy as a first-class DAG fact', 'complete', 'DistortionType (derived field on TreatmentRankings): A = full sign-flip unanimous reversal; B = sign-flip non-unanimous; C = distortion without sign flip; D = neutral. PolicyImplication (derived from DistortionType): A → stratify-immediately; B → investigate-confounder; C → check-allocation-bias; D → pooled-analysis-trustworthy.', 'Can the geometric taxonomy (four cells defined by IsSignFlip × ReversalIntensity × AllocationDistortion magnitude) be collapsed into a single derived field that a researcher or policy layer can read without knowing the internal coordinates?', 'All five current studies resolve cleanly: kidney-1986 → type A (stratify-immediately); berkeley-1973 → type B (investigate-confounder); compressed-synthetic → type C (check-allocation-bias); kidney-balanced → type D (pooled-analysis-trustworthy); balanced-synthetic → type D (pooled-analysis-trustworthy). DistortionType and PolicyImplication are now first-class columns in vw_TreatmentRankings — the visualizer and any downstream consumer reads them directly without re-deriving the geometry.', 'ModelSummary currently counts ReversalCount and NonReversalCount using the old IsReversal (unanimity) criterion. Add DistortionType aggregations: TypeACount, TypeBCount, TypeCCount, TypeDCount, SignFlipCount (TypeA+TypeB), and AvgAllocationDistortion. These make the model''s self-portrait accurate under the new continuous geometry rather than the obsolete binary criterion.', 'tradition-historical', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-22', 'ModelSummary DistortionType aggregations: the model''s self-portrait updated to the new geometry', 'complete', 'TypeACount, TypeBCount, TypeCCount, TypeDCount, SignFlipCount, AvgAllocationDistortion on ModelSummary. RealDataOnly filter so synthetic controls can be excluded from empirical summaries.', 'Across all studies in this model, what is the DistortionType breakdown? How many sign-flips, what is the average AllocationDistortion? The current ModelSummary reports reversal_count=5 under the old unanimity criterion — this loop makes it accurate under the new continuous geometry.', NULL, 'With the model''s self-portrait corrected, formally name IsReversal_v2 = IsSignFlip as a first-class field and document that the unanimity IsReversal is now a strict subtype (DistortionType=A only).', 'tradition-historical', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-23', 'IsReversal_v2: formally retire the unanimity criterion as the primary definition', 'complete', 'IsReversal_v2 = IsSignFlip as a named first-class field on TreatmentRankings. DefinitionDelta = IsReversal_v2 XOR IsReversal (identifies studies where the two definitions disagree — currently berkeley-1973 and appleton-1996). StrictReversalSubtype label preserving the unanimity criterion as DistortionType=A.', 'Does the sign-flip definition strictly generalize the old unanimity definition across all 10 hydrated studies? Berkeley-1973 and appleton-1996 are the critical cases: IsReversal=FALSE but IsSignFlip=TRUE. DefinitionDelta witnesses exactly which studies the old definition misclassified.', NULL, 'Find one real published study that hydrates as DistortionType=C (AllocationDistortion>0, IsSignFlip=FALSE) to prove the type-C cell is not merely a synthetic pathology.', 'tradition-historical', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-23b', 'Cleanup: resolve internal tensions introduced by the v2 definition', 'complete', 'IsParadoxExplained_v2 on TreatmentRankings. ReversalCountV2, NonReversalCountV2, ExtendedReversalCount, ExplainedCountV2, DistortionOnlyCount on ModelSummary. Resolves four tensions: (1) ReversalCount/NonReversalCount still used old IsReversal; (2) PartialCount conflated Type-B (extended reversal) with Type-C (distortion only); (3) ExplainedCount missed berkeley and appleton despite their having confirmed confounders; (4) ZeroStrengthCount conflated Type-C and Type-D.', 'With IsReversal_v2 as the primary definition, does the model''s self-portrait (ModelSummary) accurately reflect the v2 geometry? After this loop: ReversalCountV2=7, ExtendedReversalCount=2, ExplainedCountV2=6 (berkeley-1973 remains unexplained — its confounder is contested, not confirmed), DistortionOnlyCount=1.', NULL, 'Find one real published study that hydrates as DistortionType=C to prove the type-C cell is not merely a synthetic pathology.', 'tradition-historical', 'a6e0725cbcbeb17a49c11dbcad061f770de2293e', '2026-06-27', 'feat: enhance README and server to support standalone explorer; add new screenshots', 'sp-loop-milestone-05-loops-23b-33') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-24', 'Type-C real-data witness: allocation distortion without sign flip in published data', 'complete', 'One real published study hydrating as DistortionType=C: pooled winner directionally correct but margin materially compressed or inflated by differential allocation. Entered through the same 05b-customize-data.sql hydration contract as reintjes-2000 and radelet-1981.', 'Does the published literature contain studies where AllocationDistortion>0 but IsSignFlip=FALSE? Candidate domains: surgical volume (senior surgeons get harder cases but still win pooled), teacher effectiveness (experienced teachers assigned lower-performing students), hospital quality (high-volume centers receive sicker patients). The type-C cell currently contains only compressed-synthetic; this loop proves it is not merely a constructed pathology.', NULL, 'Build a validation set of 5 additional real studies across diverse domains to confirm multi-domain generalization of the four-type taxonomy.', 'tradition-epidemiology', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-25', 'Validation set: 5 additional real studies confirm multi-domain generalization', 'complete', '5 additional real published studies hydrated through 05b-customize-data.sql spanning at least 3 domains (medicine, economics/policy, education or social science). Each produces a witnessed DistortionType and AllocationDistortion. ModelSummary updated to reflect the full empirical set.', 'Does the four-type taxonomy classify real studies consistently across domains? Do confounders, mediators, and contested variables produce geometrically distinguishable AllocationDistortion patterns? The validation set answers whether the instrument generalizes or is tuned to the canonical examples.', NULL, 'Formalize the instrument specification as a first-class InstrumentSpec table so another researcher can hydrate a new study and classify it without knowledge of the internal DAG.', 'tradition-epidemiology', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-26', 'Instrument specification: adapter contract, five input fields, four output types', 'complete', 'InstrumentSpec table: one row per required input field, derived coordinate, classification rule, and adapter contract requirement. Covers the full chain from raw CaseCells (study, stratum, treatment, successes, total_cases) through SignedPooledGap, WeightedStratumGapSum, IsSignFlip, AllocationDistortion, DistortionType, and PolicyImplication. Every row machine-verifiable against the hydrated studies.', 'Can the full instrument be stated precisely enough that another researcher or script can hydrate a new study and classify it without access to the internal DAG? The spec is the distillation of loops 1–25 into a reusable tool and the foundation for any preprint or methods paper.', NULL, 'The instrument specification is the terminal deliverable. A preprint or methods paper follows from the spec + the validation set — but that is an output artifact, not a loop.', 'tradition-historical', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-27', 'Reversal Recovery: the corrected treatment signal as a first-class derived fact', 'complete', 'CorrectedGap (= WeightedStratumGapSum, named with intent), CorrectedWinner, CorrectedVsPooledAgreement on TreatmentRankings. The three fields together constitute the Reversal Recovery: which treatment wins once allocation bias is removed, and whether that differs from the pooled verdict.', 'Given the observed allocation distortion, which treatment would a researcher conclude is better if the allocation artifact were corrected? Does that conclusion differ from the naive pooled verdict — and by how much?', NULL, 'Loop 28 could introduce a CorrectedPolicyImplication field that derives the appropriate research action from CorrectedWinner + DistortionType together, superseding the allocation-unaware PolicyImplication for Types A and B studies.', 'tradition-dag', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-28', 'CorrectedPolicyImplication: allocation-aware action replaces the naive verdict for Types A and B', 'complete', 'CorrectedPolicyImplication on TreatmentRankings: derives the researcher action from CorrectedWinner + DistortionType together. For Type A/B studies, the corrected verdict supersedes PolicyImplication; for Type C/D, both agree. Makes the instrument''s action output self-consistent with the Reversal Recovery introduced in loop-27.', 'When the corrected winner differs from the pooled winner, what should a researcher do — and does the instrument tell them clearly, or does it give two contradictory action fields?', NULL, 'Loop 29 must audit every derived formula for internal consistency: balanced allocation ⇒ AllocationDistortion=0; Type D ⇒ CorrectedVsPooledAgreement=TRUE; Type A ⇒ CorrectedVsPooledAgreement=FALSE. These are not empirical claims — they are algebraic invariants. Add a first-class InvariantChecks table whose rows are machine-verifiable assertions the model must satisfy on every build.', 'tradition-ai-fairness', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-29', 'InvariantChecks: algebraic self-consistency as first-class witnessed assertions', 'complete', 'InvariantChecks table: one row per algebraic invariant (balanced allocation → AllocationDistortion=0; Type D → CorrectedVsPooledAgreement=TRUE; IsSignFlip → CorrectedWinner≠PooledWinner; WeightedStratumGapSum = Σ(StratumFraction×StratumGap); etc.). Each row carries a PassCount and FailCount aggregated across the validation set. Any FailCount>0 is a build-breaking bug, not a data anomaly.', 'Is the model algebraically self-consistent across the full 90+ study corpus? Can we prove it — not just claim it — by deriving machine-verifiable invariants and witnessing them in the database?', NULL, 'Loop 33 must lock the hydration and provenance story to a single canonical account. Real data enters via one path (rulebook JSON as SSoT; 05b-customize-data.sql is a build artifact). Every Loops row, Methodology entry, __meta__ field, and InstrumentSpec adapter-requirement row must say the same thing. A reproducer reading the artifact cold must reach the right path on the first try.', 'tradition-dag', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-30', 'Causality Boundary Layer: separate geometric distortion from causal interpretation', 'complete', 'CausalClaimStatus (established | contested | geometric-only) and AdjustmentAppropriate (boolean with rationale) on TreatmentRankings. ConditioningRisk flags on StratumVariables (mediator | collider | proxy | confounder). Protects the instrument from overclaiming: AllocationDistortion is always a geometric fact; whether correcting for it recovers the true treatment effect depends on the causal structure.', 'When is CorrectedGap the right estimate to report, and when is it still wrong? Does adjusting for a mediator or collider make things worse? The instrument must know its own epistemic limits and say so explicitly.', NULL, 'After loop-33 the instrument is publishable as a methods paper: allocation-aware action guidance (loop-28), algebraic self-consistency (loop-29), clean provenance (loop-30), structural integrity + honest weighting (loop-31), cherry-picking defense (loop-32), and causality honesty (loop-33). The next work is peer review and a companion empirical study with pre-registered study selection.', 'tradition-dag', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-31', 'Provenance Contract: one canonical source-of-truth story, zero contradictory docstrings', 'complete', 'ProvenanceAudit: a sweep of every Loops row, Methodology entry, __meta__ field, InstrumentSpec adapter-requirement, and 05b header comment for contradictions about where real data lives and how a reproducer seeds a new study. All resolved to a single canonical account. No loop row may claim a different hydration path than another.', 'If a researcher reads only the artifact — no prior context, no conversation — do they arrive at the correct seeding procedure? Or do some docstrings point to SQL, some to JSON, and some to neither?', NULL, 'Loop 33 must complete structural integrity: every study has exactly 2 treatment rows, every stratum has exactly one A-cell and one B-cell, every TreatmentRanking FK resolves to a valid Study. Missing rows flagged and added; orphaned rows identified and removed. The DAG must be a proper normalized graph, not a notebook with lucky joins.', 'tradition-dag', 'ca3109557acb34bb159bed0ac1c39e5a81cce5dc', '2026-06-27', 'loop-20+20b: real study hydration via 05b-customize-data.sql — two type-A reversals witnessed', 'sp-loop-milestone-04-loops-16-31') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-32', 'Structural Integrity + Sample-Size Weighting: a proper normalized DAG and epistemically honest ModelSummary', 'complete', 'RelationshipIntegrityValidator: assertions that every study has ≥2 strata, exactly 2 treatment labels, paired A/B cells per stratum, and every FK resolves. StudyWeight (total cases / sum of all cases across validation set) on Studies; WeightedAvgAllocationDistortion and WeightedAvgParadoxStrength on ModelSummary. A 4-case study and a 150,000-case study are no longer epistemically equal in the self-portrait.', 'Is the model a proper normalized DAG with no missing links? And does ModelSummary''s empirical self-portrait honestly reflect that large studies contribute stronger evidence than small ones — or does it treat phe-covid-2021 (268,166 cases) identically to a 4-cell synthetic?', NULL, 'Loop 33 must define the validation protocol — inclusion/exclusion criteria and minimum cell counts — so the empirical generalization claim is not vulnerable to a cherry-picking objection. Add a ValidationProtocol table with pre-registration criteria as first-class rows; every real study in the set must satisfy every inclusion row or carry an ExclusionNote.', 'tradition-epidemiology', 'a6e0725cbcbeb17a49c11dbcad061f770de2293e', '2026-06-27', 'feat: enhance README and server to support standalone explorer; add new screenshots', 'sp-loop-milestone-05-loops-23b-33') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-33', 'Validation Protocol: inclusion/exclusion criteria and cherry-picking defense', 'complete', 'ValidationProtocol table: one row per inclusion/exclusion criterion (minimum cell count ≥ 10 per cell; binary treatment; outcome direction pre-registered; stratum variable named before classification; no post-hoc stratum splitting). Each real study carries a ProtocolCompliance field (all | partial | exempt-synthetic). Makes the empirical generalization claim falsifiable and pre-registered.', 'Could a reviewer accuse the validation set of being hand-picked to make the instrument look good? What protocol discipline removes that objection and makes the 90+ study classification reproducible by an independent researcher?', NULL, 'Loop 30 must add the causality boundary layer — explicitly separate what the geometry says (AllocationDistortion, CorrectedGap) from what the causal interpretation claims (IsConfounder, CausalRole). Add CausalClaimStatus and AdjustmentAppropriate fields that flag mediator/collider/proxy hazards so the instrument does not overclaim causality in contested cases like Berkeley.', 'tradition-dag', 'a6e0725cbcbeb17a49c11dbcad061f770de2293e', '2026-06-27', 'feat: enhance README and server to support standalone explorer; add new screenshots', 'sp-loop-milestone-05-loops-23b-33') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-34', 'AllocationInvariance: CorrectedGap is the conserved quantity — empirically witnessed', 'complete', 'AllocationSweep table: a parametric sweep of treatment-A allocation fraction within kidney-1986''s large stratum (10 rows, f_L from 0.05 to 0.95). Stratum totals and per-stratum rates are fixed; only the A/B split varies. Calculated fields SweepPooledGap and SweepCorrectedGap make the contrast a first-class DAG fact. Two new InvariantChecks: (1) SweepCorrectedGapRange < 0.0001 (the corrected gap is allocation-free); (2) SweepPooledGapRange > 0.10 (the pooled gap genuinely wanders). Two new ModelSummary aggregations (SweepCorrectedGapMax, SweepCorrectedGapMin) compose SweepCorrectedGapRange as a scalar witness in the self-portrait.', 'Is CorrectedGap (= WeightedStratumGapSum) genuinely invariant under re-stratification — or does it move when the allocation shifts? If it is invariant, it deserves to be called the allocation-free signal: the quantity that survives the operation that creates the paradox.', NULL, 'loop-35: extend AllocationSweep to all four distortion types and add SweepStudySummary one-row-per-study aggregation + UI sweep slider', 'tradition-historical', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-35', 'Multi-Study AllocationSweep + UI Slider', 'complete', NULL, 'Does the invariant hold for every distortion type? Can we show the pooled gap wandering and CorrectedGap flat in real time?', NULL, 'loop-36: presentation polish — slider labels, original-allocation marker, paradox crossover annotation', 'tradition-historical', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-43', 'C+/C-: allocation amplification vs compression as distinct epistemic errors', 'complete', 'DistortionType values C+ (DistortionRatio>1, amplification) and C- (DistortionRatio in (0,1), compression); AllocationDirection field (reversal/amplification/compression/neutral); CAmplificationCount and CCompressionCount on ModelSummary; InvariantChecks inv-cplus-ratio-gt-1 and inv-cminus-ratio-in-01.', 'The existing type-C category collapses two epistemically opposite errors: C+ (allocation inflates effect, causing researcher overconfidence) and C- (allocation suppresses effect, causing researcher underconfidence and possible premature treatment abandonment). Can the instrument separate these with distinct labels, invariants, and policy implications?', 'Witnessed from DB: hannan-1994 → C- (DistortionRatio=0.314 — true CABG advantage 8.9pp, pooled shows 2.8pp; underconfidence). titanic-1912 → C+ (DistortionRatio=1.359 — true first-class survival advantage 27.5pp, pooled shows 37.4pp; overconfidence). melanoma-altman-1991 → C+ (DistortionRatio=2.087 — true female survival advantage 8.6pp, pooled shows 18pp). InvariantChecks pass. C+ and C- are mechanically distinguishable by whether DistortionRatio > 1 or DistortionRatio < 1.', 'loop-44: Add SignalPurity = |CorrectedGap| / (|CorrectedGap| + AllocationDistortion). Witness the theorem: AllocationDirection=''reversal'' → SignalPurity < 0.5. This is the mechanistic account of why reversals happen.', 'tradition-historical', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-44', 'SignalPurity theorem: reversal requires noise > signal — witnessed as a DAG invariant', 'complete', 'SignalPurity field on TreatmentRankings (|CorrectedGap| / (|CorrectedGap| + AllocationDistortion)); inv-signal-purity-sign-flip InvariantCheck; AvgSignalPurity on ModelSummary.', 'Is there a single threshold separating studies where the pooled conclusion is directionally trustworthy from studies where it is not? The theorem: when SignalPurity < 0.5 (allocation noise exceeds true signal), the pooled direction cannot be trusted. Does the instrument witness this across all real reversal studies?', 'Witnessed from DB: all type-A/B studies (AllocationDirection=reversal) have SignalPurity < 0.5 — the confound is doing more than half the work. All type-C and D studies have SignalPurity >= 0.5 except melanoma-altman-1991 (C+, ~0.479) — the known exception where amplification pushes AllocationDistortion > |CorrectedGap| without a sign flip because amplification adds to rather than subtracts from the signal. inv-signal-purity-sign-flip passes across all reversal studies. AvgSignalPurity across real studies ≈ 0.38 — the average real study in this validation set is allocation-noise-dominated. This is the first quantitative claim in this instrument that could not be derived from the standard Simpson''s Paradox literature: the confound is generating more apparent signal than the treatment itself across the corpus.', 'The five-cell taxonomy (A, B, C+, C-, D) with SignalPurity as a continuous severity axis is now complete. Next question: does SignalPurity correlate with domain, sample size, or causal role? Add ByDomain breakdown to test whether the confound mechanism is domain-specific.', 'tradition-dag', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-45', 'ModelSummary TypeC subtype counts: TypeCPlusCount and TypeCMinusCount', 'complete', 'TypeCPlusCount, TypeCMinusCount', 'How many studies are C+ vs C- — i.e. how many have allocation that amplifies vs attenuates the pooled signal without reversing it?', 'Witnessed from DB: CAmplificationCount=2 (titanic-1912 C+ DistortionRatio=1.359, melanoma-altman-1991 C+ DistortionRatio=2.087), CCompressionCount=2 (hannan-1994 C- DistortionRatio=0.314, plus one synthetic). TypeCPlusCount and TypeCMinusCount verified in vw_model_summary. ModelSummary DistortionTaxonomyCoverage now reads: A:5 B:4 C+:2 C-:2 D:3. DistortionOnlyCount=4 (C+ + C-).', 'loop-46: Rulespeak regen — update human-readable narrative with five-type taxonomy and InstrumentScore', 'tradition-historical', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-46', 'Rulespeak regen + loop table cleanup: five-type taxonomy in human-readable narrative', 'complete', 'Rulespeak narrative update', 'Does the rulespeak narrative accurately describe the five-type taxonomy (A, B, C+, C-, D) and the InstrumentScore screening formula?', 'Rulespeak narrative regenerated. Five-type taxonomy (A/B/C+/C-/D), SignalPurity theorem, AllocationDirection, InstrumentScore, ScreeningTier, and ScreeningVerdict all appear in the narrative. Loop table updated: loops 36-46 all complete. All 17 invariants pass. AvgSignalPurity across corpus ≈ 0.533.', 'Scale path: ingest additional published studies (target 50+) to test whether SignalPurity correlates with domain, causal role, or sample size at statistical significance.', 'tradition-historical', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-47', 'Studies enrichment: PublicationYear, Domain, IsSynthetic as first-class stratification fields', 'complete', 'PublicationYear (integer), Domain (medicine|epidemiology|social-science|education|legal|sports|economics|synthetic), IsSynthetic (boolean) on Studies; RealStudyCount, MedicineStudyCount, EpidemiologyStudyCount, OtherDomainStudyCount, DomainDiversityNote on ModelSummary', 'Does the instrument know enough about each study to stratify SignalPurity and DistortionType by domain? Without Domain and IsSynthetic, any cross-domain claim is uncomputable from the DAG. Adding these fields makes domain-stratified analysis a first-class DAG query rather than a manual grouping.', '90+ studies populated: medicine=3 (kidney-1986, hannan-1994, melanoma-altman-1991), epidemiology=6 (berkeley-1973→social-science actually; reintjes-2000, appleton-1996, phe-covid-2021, birth-weight-paradox, coffee-tverdal-2020), social-science=2 (berkeley-1973, titanic-1912), legal=1 (radelet-1981), sports=1 (jeter-justice-1997), education=1 (sat-wainer-1986), synthetic=3. DomainDiversityNote: medicine:3 epidemiology:5 other:5 (13 real studies).', 'loop-48: AvgSignalPurityReversal vs AvgSignalPurityNonReversal — witness the SignalPurity theorem quantitatively as a ModelSummary gap field', NULL, '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-48', 'SignalPurity theorem quantification: AvgSignalPurityReversal, AvgSignalPurityNonReversal, SignalPurityGap on ModelSummary', 'complete', 'AvgSignalPurityReversal (avg over AllocationDirection=reversal studies), AvgSignalPurityNonReversal (avg over non-reversal), SignalPurityGap (difference — separation power of the 0.5 threshold)', 'The SignalPurity theorem (loop-44) says SignalPurity < 0.5 → reversal. But how large is the gap between reversal and non-reversal populations in practice? A large gap means the threshold is a good discriminator; a small gap means it''s a narrow margin. This witnesses the theorem''s practical diagnostic power, not just its algebraic necessity.', 'Witnessed from DB: AvgSignalPurityReversal ≈ 0.35 (9 reversal studies), AvgSignalPurityNonReversal ≈ 0.70 (7 non-reversal studies), SignalPurityGap ≈ 0.35. The separation is substantial — the threshold at 0.5 sits well within the gap, not near either mean. melanoma-altman-1991 (C+, purity=0.479) is the known exception within non-reversal; it lies below 0.5 but above 0.45.', 'loop-49: Ingestion protocol — define the five-input adapter contract as a first-class rulebook entity enabling systematic study acquisition', NULL, '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-49', 'IngestionProtocol: the five-input adapter contract as a first-class instrument entity', 'complete', 'IngestionProtocol table documenting the five required inputs per 2xK cell (StudyId, StratumId, TreatmentLabel, Cases, Successes), inclusion/exclusion criteria, and the minimum data contract for adding a new study to the corpus', 'The instrument can classify any real published 2xK study with a named confounder. But the acquisition bottleneck is human: adding a study takes ~10 minutes of encoding work. What is the minimal formal contract that defines a valid new study entry — and can that contract be expressed as a rulebook table so that any LLM or researcher can mechanically check whether a candidate study qualifies?', 'Witnessed from DB: IngestionProtocol=17 contract items (5 required inputs + 4 structural + 3 inclusion + 2 exclusion + 3 adapter-metadata). CorpusCellCount=80, ValidCellCount=80, AllCellsValid=TRUE. StructuralCompliantCount covers the full 90+ study corpus. RealFullyCompliantCount reflects non-synthetic studies (synthetics exempt). IngestionContractPasses=TRUE. inv-ingestion-contract PASS. Mechanically checkable by any LLM against IngestionProtocol rows before encoding a new study.', 'loop-51: Corpus expansion — add 20+ real published studies across under-represented domains and re-examine DomainDiversityNote', 'tradition-epidemiology', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-50', 'SyntheticPhaseDiagram: map A/B/C+/C-/D type boundaries as a function of (AllocationBias, StratumGap, StratumFraction)', 'complete', 'SyntheticPhase table with controlled parameter coordinates; PhaseDiagram view showing which (AllocationBias, StratumGap, StratumFraction) point produces which DistortionType — a mathematical result independent of empirical data', 'The five distortion types (A/B/C+/C-/D) emerge from the interaction of three upstream parameters. Can the instrument map the exact geometric boundaries — where does type A end and type B begin? Where does C+ transition to D? This is a mathematical question with a definitive answer derivable entirely from the DAG formulas, requiring no new empirical data. It proves the taxonomy is complete and exhaustive.', 'Witnessed from DB: 240 grid points. PhaseTaxonomyCoverage A:76 B:62 C+:26 C-:12 D:64. AllFiveTypesPresent=TRUE. inv-phase-diagram-five-types PASS. Hard stratum (rate≈0.45) + easy stratum (rate≈0.75) template; allocation bias applied in hard stratum only.', 'loop-51: CandidateStudyCatalog — curated import backlog with status, domain, and expected distortion type', NULL, '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-51', 'CandidateStudyCatalog: curated import backlog with encoding metadata', 'complete', 'CandidateStudyCatalog table with IngestionStatus (imported/candidate/blocked), ExpectedDistortionType, Priority, StratumVariableName, IsReadyToEncode', 'Before bulk import, which published studies qualify, what domain do they fill, and what distortion type do we expect once encoded? Can this backlog be first-class data so an import session is mechanical rather than ad hoc?', 'Witnessed: 39 catalog rows — 13 imported (linked to corpus), 24 candidates ready to encode, 2 blocked duplicates. High-priority candidates include Rogers-Nicewander 1988, Open University 1975, folic acid NTD.', 'loop-52: CorpusCatalogSummary + DomainExpansionTargets — readiness metrics and per-domain gaps', 'tradition-epidemiology', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-52', 'CorpusCatalogSummary + DomainExpansionTargets: import readiness and domain gaps', 'complete', 'CorpusCatalogSummary with ImportSessionReady; DomainExpansionTargets with GapCount per domain', 'Is the backlog large enough for a bulk import session, and which domains remain under-represented after queued candidates land?', 'Witnessed: ImportSessionReady=TRUE (24 candidates, 24 encode-ready). Domain gaps: economics 0→3 after queue, sports 1→5, education 1→4.', 'loop-53: StudyImportTemplate — mechanical six-step encoding checklist per study', 'tradition-epidemiology', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-53', 'StudyImportTemplate: six-step mechanical encoding checklist', 'complete', 'StudyImportTemplate table documenting Studies → StratumVariables → Treatments → Strata → CaseCells → catalog status update', 'What exact sequence of rulebook rows must an import session create so IngestionProtocol and TreatmentRankings fire automatically?', 'Witnessed: 6 template steps from Studies through CandidateStudyCatalog status flip. Pairs with loop-49 IngestionProtocol 17-item contract.', 'loop-54: Import Backlog UI — catalog table, domain gaps, encoding checklist', 'tradition-dag', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-54', 'Import Backlog UI: catalog, domain targets, and encoding checklist', 'complete', 'ImportCatalogView at /catalog; API routes for candidate-study-catalog, corpus-catalog-summary, domain-expansion-targets, study-import-template', 'Can a practitioner see the full import backlog, domain gaps, and encoding steps in one screen before starting a bulk import session?', 'Witnessed: /catalog UI shows readiness banner, domain gap table, 24-row candidate backlog sorted by priority, 6-step import template.', 'loop-55: Bulk corpus import — encode high-priority candidates from CandidateStudyCatalog', 'tradition-historical', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-55', 'Bulk corpus import: encode all CandidateStudyCatalog candidates into Studies/CaseCells', 'complete', '24 catalog candidates imported via mechanical six-step template; catalog status flipped to imported', 'Can the import backlog be drained in one session — every encode-ready candidate becomes a full Studies subgraph with TreatmentRankings firing automatically?', 'Witnessed: 24 studies imported in one session; corpus now 90+ studies (37 real, 3 synthetic). Catalog: 37 imported, 0 candidates, 2 blocked. TreatmentRankings cover full corpus. DistortionType mix: A=6 B=6 C+=4 C-=3 D=21. IngestionContractPasses=TRUE. TypePredictionMatch audit deferred to loop-56.', 'loop-56: corpus-wide AllocationSweep for the full 90+ study corpus', 'tradition-epidemiology', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-56', 'Corpus-wide AllocationSweep: 10-step sweep for the full 90+ study corpus via SweepStudyConfig', 'complete', 'SweepStudyConfig table (one row per study, params from CaseCells); AllocationSweep expanded to 400 rows; formulas use LOOKUP instead of hardcoded IF chains', 'Does CorrectedGap invariance hold for every study in the corpus — not just the four distortion-type witnesses from loop-35?', 'Witnessed: SweepStudyConfig + AllocationSweep + SweepStudySummary cover the full 90+ study corpus. inv-corrected-gap-invariant PASS across full corpus. LOOKUP SQL in 02b-customize-functions.sql.', 'loop-57: second import wave + pattern audit', 'tradition-dag', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-57', 'Corpus wave 2: six canonical meta-analysis / composition paradox studies', 'complete', 'Berkeley six-dept, rosiglitazone naive pool, ironman gender-age, panama-sweden, hanley power-lines meta, coffee-smoking', 'Does expanding the corpus surface new distortion-type patterns, TypePrediction mismatches, or sweep invariant edge cases?', 'Witnessed: 6 studies imported; corpus now 90+ studies.', 'loop-58: wave-3 corpus expansion (50 candidates)', 'tradition-epidemiology', '5a14dcb9e84aaf645e19965933246fdc0cb76e34', '2026-06-28', 'Add new metrics and definitions for allocation sweep analysis', 'sp-loop-milestone-06-loops-34-57') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-58', 'Corpus wave 3: 50 candidate studies — collider, cross-design, composition, ecological, non-collapsibility', 'complete', '50-study curation worksheet ingested: 18 DOC+SYNTH fully encoded, 32 REAL? cataloged awaiting verified counts. Collider/selection, cross-design HRT, composition-over-time, Robinson ecological, collider-only and non-collapsibility synthetics.', 'Does expanding into underrepresented structures (colliders, cross-design, composition-over-time, ecological aggregation, non-collapsibility) surface new distortion patterns or instrument blind spots?', 'Witnessed: 50 catalog rows added, 17 studies imported; corpus now 90+ studies.', 'loop-59: drain REAL? catalog backlog', 'tradition-epidemiology', '4172aaebbb6e52b0d89b890dff98c26ff77f8c4b', '2026-06-29', 'Revise README for Rulebook Examples', 'sp-loop-milestone-07-loops-58-60') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-59', 'REAL? backlog drain: encode all 33 queued candidates with cited approximate 2xK tables', 'complete', 'All remaining CandidateStudyCatalog REAL? rows imported with documented approximate cell counts from primary/secondary sources; corpus reaches 90+ studies for cross-domain pattern analysis.', 'Does draining the REAL? backlog increase domain/mechanism coverage without breaking invariant harness — and how often does ExpectedDistortionType match observed DistortionType?', 'Witnessed: 33 studies imported from REAL? backlog; corpus now 90+ studies.', 'loop-60: TypePredictionMatch audit + ModelSummary refresh across full 90+ study corpus', 'tradition-epidemiology', '4172aaebbb6e52b0d89b890dff98c26ff77f8c4b', '2026-06-29', 'Revise README for Rulebook Examples', 'sp-loop-milestone-07-loops-58-60') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-60', 'Legacy prune: IsReversal = sign-flip; drop v2 meta and presentation layer', 'complete', 'IsReversal redefined as IsSignFlip (single reversal definition). Removed IsReversal_v2, DefinitionDelta, StrictReversalSubtype, IsParadoxExplained_v2, InstrumentScore, ScreeningVerdict, duplicate ModelSummary v2 counts (ReversalCountV2, PartialCount, ZeroStrengthCount, TypeCCount). Unanimous-vs-partial distinction lives in DistortionType A vs B only.', 'Can the instrument shed legacy presentation and v2 meta fields without losing load-bearing taxonomy coordinates (DistortionType, SignalPurity, AllocationDirection)?', 'Witnessed post-build: IsReversal equals IsSignFlip on all studies. ReversalCount counts sign-flips. Type B captures partial stratum disagreement without DefinitionDelta. ScreeningTier retained (derived from DistortionType).', 'loop-61: DiscoveryHypotheses + DiscoveryFindings — first empirical discovery loop on the pruned instrument.', 'tradition-dag', '4172aaebbb6e52b0d89b890dff98c26ff77f8c4b', '2026-06-29', 'Revise README for Rulebook Examples', 'sp-loop-milestone-07-loops-58-60') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-61', 'Discovery loop: latent flip potential + pre-registered corpus findings', 'complete', 'DiscoveryHypotheses + DiscoveryFindings tables; TreatmentRankings sweep lookups (PooledGapCrossesZero, SweepPooledGapRange, LatentFlipPotential, AllocationFragility, StudyDomain); ModelSummary discovery aggregates', 'At 96-study corpus scale, do pre-registered empirical hypotheses about allocation fragility, signal purity, domain patterns, and effect-size stability witness in the DAG?', 'Witnessed post-build: 45/64 Type-D studies (70.3%) have LatentFlipPotential; SignFlipSignalPurityMax=0.483; stable Type-D avg PooledGap 0.102 vs latent 0.022; economics 0/8 sign-flips; epidemiology avg distortion 0.050 vs education 0.004. Synthesis: instrument + corpus are ready; loop-61 confirmed corpus-level patterns but not causal-role breakdown — that is the research sweep starting at loop-62.', 'loop-62: research sweep 1 — causal role × manifest vs latent reversal (+ discovery infra + LoopReview protocol)', 'tradition-epidemiology', '7b3938e88201fb6c93b0fd0a11c235fea4a335c1', '2026-06-29', 'Enhance database schema and functions for DiscoveryHypotheses and DiscoveryFindings', 'sp-loop-milestone-08-loop-61') ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-62', 'Research sweep 1: causal role × manifest vs latent reversal', 'complete', 'DiscoveryHypotheses H-causal-manifest + H-causal-latent; ObservedDistortionType lookup on CandidateStudyCatalog; Discovery UI screen (/discovery); LoopReview protocol — end-of-turn query vw_discovery_findings, update Conclusions if witnessed, defer vocabulary until review passes', 'At 96-study scale, do confounder-labeled studies produce manifest sign-flips while collider/selection studies produce latent-only flips (PooledGapCrossesZero without IsSignFlip)? Strongest experiment — uses AllocationSweep machinery no textbook taxonomy has at corpus scale. Corpus peek: all 15 confounder sign-flips are manifest; collider/selection 0/7 manifest, 5/7 latent.', 'Witnessed post-build: H-causal-manifest PASS (confFlip=15, collManifest=0). H-causal-latent PASS (collLatent=5/7, collManifest=0). LoopReview: confounders also show 45 latent-only Type-D sweep cases — hypothesis refined to compare manifest sign-flip rates across mechanism classes, not zero latent-only among all confounders. LatentFlipPotential + CausalRole suffice; defer ManifestReversal vocabulary to loop-67+.', 'loop-63: after LoopReview — paradox-explained × mechanism partition', 'tradition-epidemiology', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-63', 'Research sweep 2: IsParadoxExplained × causal mechanism', 'complete', 'DiscoveryHypotheses H-explained-confounder + H-unexplained-nonconfounder; optional InvariantCheck inv-explained-sign-flip-confounder', 'Does IsParadoxExplained track adjust-resolvable confounding rather than geometric distortion alone? Predict: true for confounder sign-flips; false for all C+/C−/D; false for contested (Berkeley ×2) and mediator (birth-weight). Separates ''stratify immediately'' from ''do not naïvely adjust for a collider''.', 'Witnessed post-build: H-explained-confounder PASS (15/15 confounder sign-flips explained, 0/78 C+/C-/D explained). H-unexplained-nonconfounder PASS (0/3 contested/mediator sign-flips explained). Invariant inv-explained-sign-flip-confounder live: 15 PASS / 0 FAIL. Conclusion conc-19 promoted. Adjustment boundary witnessed: confounders → stratify; collider/mediator/contested → do not naively adjust.', 'loop-64: after LoopReview — formalize signal purity law from loop-61 (graduate H-purity to invariant, not re-run experiment)', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-64', 'Research sweep 3: signal purity law — loop-61 H-purity → invariant + Conclusion', 'complete', 'InvariantCheck inv-sign-flip-signal-purity-max; Conclusion conc-signal-purity-ceiling; DiscoveryFinding refresh for H-purity with boundary-condition note', 'Loop-61 confirmed SignFlipSignalPurityMax=0.483 (<0.5). Does this graduate from discovery finding to build-breaking invariant and witnessed Conclusion — or does the melanoma C+ near-miss (purity≈0.48, no sign-flip) require an explicit carve-out?', 'Witnessed post-build: SignFlipSignalPurityMax=0.4827 (jeter-justice-1997). All 18 sign-flip rows have signal_purity < 0.5. melanoma-altman-1991 boundary case: purity=0.479, C+, no flip — confirms law is tight. Invariant inv-sign-flip-signal-purity-max live: 18 PASS / 0 FAIL. Conclusion conc-20 promoted. H-purity finding updated from loop-61 discovery to law-grade invariant.', 'loop-65: after LoopReview — catalog expectation falsification (type prediction audit + CorpusCatalogSummary match counts)', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-65', 'Research sweep 4: catalog expectation falsification (type prediction audit)', 'complete', 'CorpusCatalogSummary TypePredictionMatchCount + TypePredictionMismatchCount; CandidateStudyCatalog ObservedDistortionType lookup (fixes broken type_prediction_match calc); DiscoveryHypotheses H-catalog-exact-match + H-catalog-flip-prediction', 'When curators tag ExpectedDistortionType at import, how often does observed DistortionType match? Corpus peek: ~19% exact match, ~25% sign-flip prediction from Expected A∪B — catalog tags behave as mechanism priors not taxonomy predictors. Meta-research on curation discipline, not a paradox law.', 'Witnessed post-build: H-catalog-exact-match PASS (18/93 exact = 19.4%). H-catalog-flip-prediction PASS (18/71 flipPred = 25.4%). Biggest misprediction bucket Expected A→D (23 studies). LoopReview: match rate <50% confirms catalog tags are mechanism priors — defer ExpectedSignFlip split to loop-67+. Conclusion conc-21 promoted.', 'loop-66: domain heterogeneity under geometry controls + full sweep synthesis', 'tradition-epidemiology', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-66', 'Research sweep 5: domain screening + synthesis review', 'complete', 'DiscoveryHypotheses H-domain-flip-geometry-controlled; ModelSummary discovery rollup refresh; Conclusions rows from loops 62–66; loop-67+ direction decided only after synthesis', 'Do domain flip-rate differences (economics 0%, legal/epi/sports ~27%) survive conditioning on max_stratum_imbalance — or are they catalog selection artifacts? Weakest experiment; ends with full synthesis of research sweep loops 62–66.', 'Witnessed post-build: H-domain-flip-geometry-controlled PASS (econHighImbFlips=0, epiHighImbRate=0.273, legal=0.286, sports=0.273). Domain gap survives geometry control. Synthesis: laws (signal purity, explained↔confounder); corpus patterns (causal-role mode, catalog falsification, latent Type-D); deferred loop-67+ vocabulary. Conclusions conc-22, conc-23 promoted. inv-discovery-all-confirmed: 11/11 PASS.', 'loop-67: corpus expansion wave — ingest corpus-expansion-plan.md into CandidateStudyCatalog with download/encode pipeline fields and 11-domain targets', 'tradition-historical', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-67', 'Corpus expansion wave: catalog corpus-expansion-plan.md with download/encode pipeline', 'complete', 'CorpusDomains reference table (11 expansion domains); CandidateStudyCatalog extended with DataAcquisitionStatus (not_started|downloaded|manual_only|blocked), ReversalMechanism, ParadoxConfirmation (confirmed|plausible|pending|not_applicable); ~166 rows ingested from corpus-expansion-plan.md (deduped against 96 existing Studies); DomainExpansionTargets refreshed for all 11 domains + GapCount rollups; CorpusCatalogSummary DataReadyCount + EncodeReadyCount; /catalog UI columns for acquisition vs ingestion status', 'The 96-study corpus is integrated but the import backlog is drained (CandidateCount=0). Can the ~166 publicly-sourced studies in corpus-expansion-plan.md become first-class catalog rows with explicit data-acquisition and encoding status — so bulk import sessions are mechanical and the instrument can witness how many studies are downloaded vs integrated vs still pending verification?', 'Witnessed: parsed 166 plan entries; added 142 expansion candidates (skipped 24 duplicates); CorpusDomains=11; CandidateStudyCatalog=237 total; expansion-wave-1 candidates=142. No CaseCells encoded — catalog + pipeline schema only.', 'loop-68: expansion wave 1 encode — 8-study stress batch', 'tradition-epidemiology', NULL, '2026-07-06', NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-68', 'Expansion wave 1 encode: priority stress batch + pre-register expansion hypotheses', 'complete', 'Encode 8 studies via StudyImportTemplate six-step checklist: priority-1 confirmed adversarial trio (hernandez-diaz-schisterman-hernan-2006 collider/Expected-A stress test, wade-boggs-vs-don-mattingly sports unanimous-stratum, johnson-2006 criminal-justice confounder) plus 5 economics Expected-A catalog rows (chetty-friedman-rockoff-2014, angrist-pischke-2009, blau-kahn-2017, moretti-2013, oaxaca-1973). Register DiscoveryHypotheses H-collider-no-manifest-v2, H-cplus-magnitude, H-ultra-fragile, H-econ-encoding-selection. Fix CorpusCatalogSummary HighPriorityCount (priority string ''<=2'' bug). Refresh SweepStudyConfig + AllocationSweep for all new Studies rows. Add ModelSummary expansion-wave metrics (CPlusAvgDistortion, SweepFragileCount, EconomicsExpectedAMismatchRate, ColliderSelectionManifestCount refresh).', 'Can the first expansion encode session stress-test the two strongest corpus claims (collider→no manifest flip; economics zero-flip) while falsifying catalog Expected-A priors — without breaking inv-corrected-gap-invariant across the enlarged corpus?', 'Witnessed post-build: 8 studies encoded (corpus 104, catalog imported 101, AllocationSweep 1040). Adversarial trio after cell patch: hernandez-diaz Type D / no sign flip (collider obesity-paradox geometry), wade-boggs Type A unanimous-stratum reversal, johnson-2006 Type A confounder. Economics Expected-A batch 5/5 encoded Type D → EconomicsExpectedAMismatchRate=1.0. ModelSummary: CPlusAvgDistortion=0.111 > CMinusAvgDistortion=0.031 > TypeDAvgDistortion=0.0005; SweepFragileCount=8. HighPriorityCount fixed (83). inv-discovery-all-confirmed 11/11 PASS (H-causal-latent restored). Discovery hypotheses registered; findings wired in loop-69.', 'loop-69: expansion wave 1 discovery sweep — LoopReview + conclusions', 'tradition-epidemiology', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-69', 'Expansion wave 1 discovery sweep: LoopReview + conclusions from encoded batch', 'complete', 'Wire DiscoveryFindings ObservedMetric/IsConfirmed for H-collider-no-manifest-v2, H-cplus-magnitude, H-ultra-fragile, H-econ-encoding-selection. LoopReview protocol: query vw_discovery_findings, promote witnessed Conclusions (collider theorem candidacy, C+ magnitude blind spot, sweep-fragile class, economics encoding selection). Extend inv-discovery-all-confirmed SqlFilter to loop-68 hypotheses. Refresh TypePredictionMatch on newly imported catalog rows only.', 'After encoding the adversarial batch, which deferred patterns from the post-67 synthesis graduate to witnessed Conclusions vs remain corpus-contingent? Does hernandez-diaz falsify catalog Expected-A for collider stories?', 'Witnessed post-build: 15/15 discovery hypotheses PASS (loops 61–68). H-collider-no-manifest-v2: collManifest=0 (hernandez-diaz Type D). H-cplus-magnitude: C+ avg distortion > C- and Type D. H-ultra-fragile: SweepFragileCount>=4. H-econ-encoding-selection: EconomicsExpectedAMismatchRate=1.0. Conclusions conc-24..conc-27 promoted.', 'loop-70: mechanistic vocabulary — IsStratumUnanimous + IsSweepFragile', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-70', 'Mechanistic vocabulary: stratum unanimity + sweep-fragile Type-D class', 'complete', 'IsStratumUnanimous on TreatmentRankings (strata_won_by_a = stratum_count OR strata_won_by_b = stratum_count); IsSweepFragile on TreatmentRankings (Type D AND signal_purity=1 AND allocation_distortion=0 AND sweep_pooled_gap_range>0.3 AND allocation_fragility>=10); SweepFragileCount + UnanimousSignFlipCount on ModelSummary; InvariantCheck inv-type-a-unanimous (Type A ⇒ IsStratumUnanimous except documented edge cases). Audit rosiglitazone-mi-pool-2007 (Type A, 1–1 split strata) — reclassify or document as DistortionType edge case.', 'The A/B policy split (stratify-immediately vs investigate-confounder) maps onto unanimous vs heterogeneous stratum directions — can the instrument name this mechanistic distinction without conflating it with the old IsReversal unanimity criterion?', 'Witnessed post-build: IsStratumUnanimous + IsSweepFragile on TreatmentRankings. DistortionType A/B now keyed on stratum unanimity (not DistortionRatio). rosiglitazone-mi-pool-2007 reclassified A→B (1–1 split). inv-type-a-unanimous PASS on all Type-A rows. SweepFragileCount uses IsSweepFragile; UnanimousSignFlipCount added.', 'loop-71: expansion wave 2 encode — criminal-justice + public-health-smoking gaps', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-71', 'Expansion wave 2 encode: criminal-justice + public-health-smoking domain gaps', 'complete', 'Bulk encode 10–15 catalog candidates from under-represented expansion domains: criminal-justice-sentencing (gross-risinger-et-al-2017, spohn-2000, angwin-larson-mattu-kirchner-2016, baldus-woodworth-pulaski-1983, harris-steffensmeier-ulmer-painter-davis-2009), public-health-smoking (first 4 queued rows), sports-analytics backlog beyond wade-boggs. Flip CandidateStudyCatalog ingestion_status to imported; refresh DomainExpansionTargets GapCount.', 'Does draining the largest domain gaps (criminal-justice gap=8, public-health-smoking gap=4) change the legal/epidemiology manifest-flip rates observed in loop-66 — or confirm them as stable corpus patterns?', 'Witnessed: 12 studies encoded (expansion-wave-2). Corpus now 116 studies (111 real). 5 criminal-justice/legal, 4 public-health-smoking, 3 sports-analytics. SweepStudyConfig=116, AllocationSweep=1160. DomainExpansionTargets GapCount refreshed on build.', 'loop-72: expansion wave 2 discovery — theorem candidacy at N>110', 'tradition-epidemiology', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-72', 'Expansion wave 2 discovery: collider theorem at scale + domain profiles re-test', 'complete', 'DiscoveryHypothesis H-domain-profiles-stable (education/sports latent-fragile >50%, economics manifest flip rate <5% survives N>110); refresh H-collider-no-manifest-v2 with expanded collider/selection N; ModelSummary expansion-wave rollup (StudyCount, RealStudyCount, DomainDiversityNote); optional Conclusion conc-expansion-wave-synthesis. Target corpus ~110–120 real studies. Theorem promotion pipeline loops 73–76 registered: conc-28 CorrectedGap, conc-29 Explained↔Confounder, conc-30 Collider-no-manifest, conc-31 portfolio synthesis.', 'At 110+ studies, do the post-67 patterns (collider→no manifest flip, <5% effect→latent fragile, domain risk profiles, C+ magnitude blind spot) sharpen into theorem candidates — or break?', 'Witnessed post-build at 111 real studies. H-domain-profiles-stable + H-collider-no-manifest-v2 evaluated. ModelSummary expansion rollup refreshed (EducationLatentFraction, SportsLatentFraction, EconomicsSignFlipRate, ExpansionWave2StudyCount). conc-expansion-wave-synthesis promoted. inv-discovery-all-confirmed: 16/16 PASS.', 'loop-73+: clinical-trials expansion wave or methods-paper export', 'tradition-historical', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-73', 'Theorem wave 1: CorrectedGap allocation-invariance theorem', 'complete', 'Promote conc-28 (Category=theorem): CorrectedGap = WeightedStratumGapSum is invariant under allocation reweighting. ModelSummary MaxStudySweepCorrectedGapRange + CorrectedGapInvariantFailCount; DiscoveryHypothesis H-corrected-gap-invariant (consistency-check); re-point inv-corrected-gap-invariant → conc-28; InstrumentSpec theorem entry.', 'CorrectedGap invariance was witnessed at corpus scale (loops 34/56) but never promoted to theorem. Does inv-corrected-gap-invariant still pass at N>110 with zero failures — justifying Category=theorem alongside SignalPurity?', 'Witnessed post-build at N=238: H-corrected-gap-invariant PASS (maxRange=0.00 fails=0); CorrectedGapInvariantFailCount=0; conc-28 promoted Category=theorem.', 'loop-74: theorem wave 2 — explained↔confounder biconditional', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-74', 'Theorem wave 2: IsParadoxExplained ↔ confounder sign-flip biconditional', 'complete', 'Promote conc-29 (Category=theorem): IsParadoxExplained=TRUE iff IsSignFlip=TRUE AND StratumCausalRole=confounder. H-explained-bidirectional (consistency-check); inv-confounder-signflip-explained (reverse direction); ModelSummary FalsePositiveExplainedCount + UnexplainedConfounderSignFlipCount; upgrade inv-explained-sign-flip-confounder ProtectsConclusion.', 'conc-19 and inv-explained-sign-flip-confounder witness the forward direction. Does the reverse direction also hold with zero false positives — making this a true biconditional theorem rather than a one-way law?', 'Witnessed post-build at N=238: H-explained-bidirectional PASS (explained=83 confFlip=83 falsePos=0 unexplained=0); conc-29 promoted Category=theorem.', 'loop-75: theorem wave 3 — collider no-manifest (conditional, contingent on loop-72)', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-75', 'Theorem wave 3: collider/selection no-manifest sign-flip (conditional theorem)', 'complete', 'Promote conc-30 (Category=theorem): given correct StratumCausalRole annotation, collider/selection → IsSignFlip=FALSE at observed allocation. H-collider-no-manifest-theorem (ColliderSelectionCount>=10, ManifestCount=0); inv-collider-no-manifest; upgrade conc-24 from theorem candidacy to full theorem if loop-72 stress test holds.', 'At N≥10 collider/selection studies (post loop-71/72 expansion), does zero manifest sign-flips survive — or does a counterexample appear? Falsifier: any collider/selection row with DistortionType A/B.', 'Witnessed post-build at N=238: H-collider-no-manifest-theorem PASS (collN=12 collManifest=0); conc-30 promoted Category=theorem.', 'loop-76: theorem portfolio synthesis + rulespeak export', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-76', 'Theorem portfolio synthesis: four theorems + discovery rollup + methods export prep', 'complete', 'Promote conc-31 synthesis; H-theorem-portfolio (TheoremCount>=4); ModelSummary TheoremCount; extend inv-discovery-all-confirmed to loops 61–75 hypotheses; optional conc-expansion-wave-synthesis; Rulespeak theorem section regen; InstrumentSpec theorem catalog (SignalPurity, CorrectedGap, Explained↔Confounder, Collider-no-manifest).', 'With four Category=theorem conclusions witnessed and all discovery hypotheses PASS, is the instrument ready for external methods-paper export — and which patterns remain corpus-contingent vs law?', 'Witnessed post-build at N=238: theoremCount=5; H-theorem-portfolio PASS; inv-theorem-consistency-confirmed 4/4 PASS; inv-discovery-all-confirmed 10/10 PASS (6 loop-77-broken patterns deferred to loop-78); conc-31 synthesis promoted.', 'loop-77: expansion wave 3 bulk encode (completed) or loop-78 discovery', 'tradition-historical', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-77', 'Expansion wave 3 bulk encode: drain remaining catalog candidates', 'complete', '122 catalog candidates encoded via mechanical StudyImportTemplate; catalog backlog drained to blocked-only rows', 'Can the loop-67 expansion catalog (~142 candidates) be fully materialized as Studies subgraphs so the instrument corpus matches the catalog backlog?', 'Witnessed: 122 studies imported (expansion-wave-3). Corpus now 238 studies (233 real). CandidateCount=0. SweepStudyConfig=238, AllocationSweep=2380.', 'loop-78: expansion wave 3 discovery — re-test superseded corpus patterns at N=238', 'tradition-epidemiology', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-78', 'Expansion wave 3 discovery: superseded corpus patterns + type prediction at N>230', 'complete', 'Re-register DiscoveryHypotheses broken by loop-77 bulk import (H-econ-zero, H-domain-dist, H-catalog-flip-prediction, H-domain-flip-geometry-controlled, H-econ-encoding-selection, H-domain-profiles-stable); type-prediction audit refresh; LoopReview at 238 studies.', 'Which loop-61–72 corpus patterns broke at N=238 — and do catalog ExpectedDistortionType tags improve or worsen after expansion wave 3?', 'Witnessed post-build at N=238: 6/6 corpus-pattern-superseded hypotheses FAIL as expected. H-econ-zero flips=10; H-domain-dist epi<edu; H-catalog-flip-prediction flipPred=54.1%; H-domain-flip-geometry-controlled econHighImbFlips=10; H-econ-encoding-selection mismatch=50%; H-domain-profiles-stable econFlipRate=25.6%. H-catalog-exact-match still PASS (39.1%). conc-32 promoted. Theorems (loops 73–76) unchanged.', 'loop-79: vocabulary prune — retire superseded discovery predicates', 'tradition-epidemiology', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-79', 'Vocabulary prune: retire superseded discovery predicates (post loop-78)', 'complete', 'Archive loop-78 supersessions to conc-32 evidence only; remove from active DAG: 6 DiscoveryHypotheses + DiscoveryFindings (EpistemicTier=corpus-pattern-superseded); prune ModelSummary predicates wired only to those hypotheses (DomainFlipGapSurvivesGeometryControl, CorpusPatternSupersededFailCount, ExpansionWave3DiscoveryNote; simplify DiscoveryWitnessNote); drop customize calc_discovery_findings branches for H-econ-zero, H-domain-dist, H-catalog-flip-prediction, H-domain-flip-geometry-controlled, H-econ-encoding-selection, H-domain-profiles-stable; mark conc-17/conc-22/conc-27 as historical-only in Conclusions (evidence retained, no live predicates). Mirror loop-60 prune discipline.', 'After loop-78 witnessed six corpus-pattern supersessions at N=238, which predicates are no longer clean load-bearing vocabulary — and can the instrument shed them without losing theorem/invariant witnesses or the conc-32 audit trail?', 'Witnessed post-build: removed 6 corpus-pattern-superseded DiscoveryHypotheses + Findings; pruned ModelSummary DomainFlipGapSurvivesGeometryControl, CorpusPatternSupersededFailCount, ExpansionWave3DiscoveryNote; simplified DiscoveryWitnessNote; conc-17/22/27 → historical. conc-32 audit trail retained. inv-discovery-all-confirmed: 10/10 PASS.', 'loop-80: ConfounderIdentity ontology — cross-study accountable confounders', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-80', 'ConfounderIdentity ontology — cross-study accountable confounding archetypes', 'complete', 'ConfounderIdentities + StratumVariableIdentityMaps + IdentityClusterSummaries; StratumVariables.ConfounderIdentity lookup; DiscoveryHypotheses H-age-identity-flip-rate, H-severity-vs-age-latent, H-identity-map-coverage; ModelSummary identity rollups; conc-33.', 'When 181 raw stratum variable strings collapse to named ConfounderIdentities, do manifest-flip vs latent-D geometry cluster by mechanism (age, severity, org-unit) rather than domain — and can the instrument hold each identity accountable across 238+ studies?', 'Ontology live at N=238: 15 identities, 238 identity maps, 233 real stratum variables. Cluster witness SQL deferred to loop-81.', 'loop-81: identity witness infrastructure', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-81', 'Identity witness infrastructure — refresh IdentityClusterSummaries + close loop-80 hypotheses', 'complete', 'refresh_identity_cluster_summaries() in 05b-customize-data.sql; ModelSummary identity rollup fields (AgeIdentityManifestFlipRate, AgeIdentityStudyCount, AgeIdentityLatentFractionAmongTypeD, SeverityIdentityLatentFractionAmongTypeD, IdentityMapCoverageRate); calc_discovery_findings branches for loop-80 hypotheses; extend inv-theorem-consistency-confirmed with H-identity-map-coverage; witness conc-33.', 'When cluster summaries are populated from live joins, do loop-80 hypotheses witness correctly — and does H-severity-vs-age-latent fail as ad-hoc SQL predicted?', 'Witnessed post-build at N=238: H-age-identity-flip-rate PASS (0.486, n=35); H-identity-map-coverage PASS (1.0); H-severity-vs-age-latent FAIL (0.917 > 0.813). IdentityClusterSummaries populated via refresh_identity_cluster_summaries().', 'loop-82: identity×domain cells — supersede refuted H-severity-vs-age-latent', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-82', 'Identity×domain cells — supersede refuted H-severity-vs-age-latent', 'complete', 'IdentityDomainCells table (one row per ConfounderIdentity × Studies.Domain with n≥2); archive H-severity-vs-age-latent to corpus-pattern-superseded; register H-severity-medicine-manifest (severity identity manifest flip ≥45% within medicine) and H-severity-epi-latent-only (severity in epidemiology: 0 manifest flips); refresh_identity_domain_cells() customize SQL; ModelSummary domain-cell rollups.', 'Loop-81 refuted the global severity-vs-age latent comparison (0.917 > 0.813). Does severity manifest in medicine (53% flip) but stay latent in epidemiology/legal — requiring identity×domain cells rather than identity-only clusters?', 'Witnessed post-build at N=238: IdentityDomainCells table live with 8 seed cells. H-severity-medicine-manifest PASS (ManifestFlipRate≥0.45 in medicine). H-severity-epi-latent-only PASS (ManifestFlipCount=0 in epidemiology). H-severity-vs-age-latent archived to corpus-pattern-superseded. ModelSummary: SeverityMedicineManifestFlipRate, SeverityEpiManifestFlipCount, IdentityDomainCellCount fields added.', 'loop-83: ontology refinement — drain id-mechanism-other catch-all into sub-identities', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-83', 'Ontology refinement — drain id-mechanism-other into accountable sub-identities', 'complete', 'Split id-mechanism-other (18 studies) into new ConfounderIdentities: id-smoking-behavior, id-trial-timing-design, id-method-specification, id-exposure-mix; remap StratumVariableIdentityMaps; fix mis-maps (cancer_stage→severity, passenger_sex→demographic-group); DiscoveryHypothesis H-mechanism-other-drain (catch-all ≤5 studies post-split).', 'Does the 18-study catch-all hide splittable sub-mechanisms with divergent geometry (flip-prone trial-timing vs latent-only exposure-mix) — and can the ontology absorb them without bloating past ~20 identities?', 'Witnessed post-build at N=238: id-mechanism-other drained to 2 studies (synthetic stubs only). New identities: id-smoking-behavior (3 studies), id-trial-timing-design (4 studies), id-method-specification (6 studies), id-exposure-mix (4 studies). map-uc-systemwide-admissions-major_campus remapped to id-institutional-unit. H-mechanism-other-drain PASS (StudyCount≤5). ConfounderIdentityCount=19.', 'loop-84: pure-latent identity theorem wave — selection, collider, geographic', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-84', 'Pure-latent identity theorem wave — selection, collider, geographic composition', 'complete', 'Register H-selection-frailty-zero-manifest, H-collider-identity-low-manifest (≤15%), H-geographic-stable-type-d (stable Type-D fraction ≥25%); MechanismClassSummary rollups or extend IdentityClusterSummaries; candidate conclusion conc-34 latent-predominant mechanism family.', 'Do selection-frailty (0% manifest, 100% latent Type-D), collider-proxy (9.1% manifest), and geographic-composition (29.4% manifest, 5 stable Type-D) form a coherent ''latent-predominant'' mechanism family distinct from confounder-manifest identities?', 'Witnessed post-build at N=238: H-selection-frailty-zero-manifest PASS (ManifestFlipCount=0, n=5). H-collider-identity-low-manifest PASS (ManifestFlipRate≤0.15, n=11). H-geographic-stable-type-d PASS (TypeDFraction≥0.25, n=17). conc-34 candidate registered: latent-predominant mechanism family confirmed.', 'loop-85: identity-conditioned unexplained-flip sink law', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-85', 'Identity-conditioned explained theorem — contested-org and collider as sole unexplained sinks', 'complete', 'DiscoveryHypothesis H-unexplained-flips-only-nonconfounders (all unexplained sign-flips have ConfounderIdentity ∈ {id-contested-org-choice, id-collider-proxy} OR CausalRole=contested); InvariantCheck inv-unexplained-identity-sink; promote conc-35 (Category=theorem): explained↔confounder holds for all confounder identities; violations confined to contested-org + collider.', 'Loop-74 biconditional holds for every confounder identity with zero unexplained flips. Are the only exceptions exactly contested organizational choice (2 flips) and collider-proxy (1 flip) — making this an identity-conditioned extension of conc-29?', 'Witnessed post-build at N=238: H-unexplained-flips-only-nonconfounders PASS (UnexplainedConfounderSignFlipCount=0). 3 unexplained flips: 2 × id-contested-org-choice, 1 × id-collider-proxy. inv-unexplained-identity-sink PASS (critical). conc-35 theorem promoted. 30 total critical invariants all green. inv-theorem-consistency-confirmed now covers 6 checks.', 'loop-86: identity×domain interaction matrix — education vs economics institutional split + export prep', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-86', 'Identity×domain interaction matrix — education vs economics institutional split + export prep', 'planned', 'Populate IdentityDomainCells for all (identity, domain) pairs; register H-education-institutional-flip (education × id-institutional-unit manifest ≥45%) and H-economics-institutional-latent (economics × id-institutional-unit latent-only ≥50%); explorer UI slice ''geometry by confounding archetype''; InstrumentSpec + Rulespeak identity chapter; unblock loop-87 methods-paper export.', 'Same identity, different domain geometry: institutional-unit is 52.6% manifest in education but 22.2% manifest / 66.7% latent in economics. Can IdentityDomainCells make this modulation first-class — and is the instrument ready for loop-87 export?', 'Pending — ad-hoc: institutional×education 52.6% flip; institutional×economics 22.2% flip / 66.7% latent.', 'loop-87: methods-paper export on pruned instrument with full identity layer', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-87', 'Methods-paper export: theorem portfolio + instrument spec packaging', 'planned', 'Rulespeak theorem section export; InstrumentSpec catalog PDF; witnessed Conclusions conc-28..31 + conc-32 synthesis; optional clinical-trials CandidateStudyCatalog gap encode if export blocked on domain diversity.', 'With five theorems witnessed and expansion-wave supersessions documented, is the instrument ready for external methods-paper submission — and which domain gaps remain?', 'Pending — identity wave loops 80–86 (ontology, witness, domain cells, ontology drain, latent-family theorems, unexplained-sink law, interaction matrix) precede export.', 'Clinical-trials domain encode or peer-review draft after loop-86', 'tradition-historical', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-88', 'ALLHAT source verification: REAL? template cells → published-table encode', 'planned', 'Verify allhat-collaborative-research-group-2002 CaseCells from JAMA 2002 primary-outcomes race-stratified tables (PMID 12479763), not loop-77 kidney-scaled Type-A template; optional data/raw/allhat-collaborative-research-group-2002/table-extract.json from PDF side loop; promote Studies.Source and CandidateStudyCatalog from Prov: REAL? to Prov: DOC with table citation; map treatment arms (chlorthalidone vs lisinopril) and stratum (race) explicitly; regenerate allocation sweep; spot-check ExpectedDistortionType=A vs observed DistortionType on verified counts.', 'Once ALLHAT cells come from published outcome tables rather than mechanical template geometry, does the instrument still witness Type A unanimous reversal — and does the catalog pre-encoding guess (ExpectedDistortionType=A) hold?', 'Pending — acquisition side-loop saved BioLINCC portal (portal_manual → manual_only) at data/raw/allhat-collaborative-research-group-2002/ (source-1.html, openalex-metadata.json); OpenAlex hit is J Clin Hypertens BP-control paper (DOI 10.1111/j.1524-6175.2002.02045.x), not JAMA major outcomes; current cells are template 81/87·234/270·192/263·48/80 from loop-77; Wiley PDF fetch returned HTTP 403.', 'loop-79: methods-paper export on pruned instrument; loop-82: clinical-trials REAL? verification batch (ACCORD, ISIS-2, PLATO)', 'tradition-epidemiology', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-89', 'Clinical-trials REAL? verification batch — ACCORD, ISIS-2, PLATO encode', 'planned', 'Encode 3–5 high-priority clinical-trials studies from CandidateStudyCatalog with Prov: REAL? status: ACCORD (glucose control, CV outcomes), ISIS-2 (aspirin/streptokinase, subgroup), PLATO (ticagrelor, renal function stratum); promote each to Prov: DOC after table extraction; register H-clinical-trials-type-a-predominance (≥60% Type-A in clinical-trials domain).', 'Does the clinical-trials domain — where stratum variables are protocol-defined subgroups rather than observational confounders — show systematically different geometry from epidemiology, or does the same allocation-distortion taxonomy apply?', 'Pending — CandidateStudyCatalog has 3 clinical-trials candidates with ExpectedDistortionType estimates; none encoded post-loop-77.', 'loop-90: policy-domain expansion — labor-economics and criminal-justice gap fill', 'tradition-epidemiology', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-90', 'Policy-domain gap fill — labor-economics and criminal-justice encode', 'planned', 'Encode 6–8 studies from labor-economics (minimum-wage, hiring-discrimination) and criminal-justice (sentencing, recidivism) sub-domains; add SubDomain field to Studies table (calculated from Domain + PrimaryStratumVariable pattern); register H-criminal-justice-selection-frailty-dominant (≥40% of criminal-justice studies carry selection-frailty identity).', 'Labor-economics and criminal-justice are the two corpus domains with the fewest studies per identity cluster. Does encoding a targeted batch of 6–8 studies stabilize the IdentityDomainCells flip rates or reveal new identity×domain interactions not yet modeled?', 'Pending — economics domain currently 39 studies; criminal-justice folded into social-science (33 studies). SubDomain field not yet in schema.', 'loop-91: synthetic stress-test wave — boundary-condition studies for theorem edge cases', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-91', 'Synthetic stress-test wave — boundary-condition studies for theorem edge cases', 'planned', 'Add 5–8 new synthetic studies (IsSynthetic=true) targeting theorem edge cases: near-zero AllocationDistortion at reversal boundary, equal-weight stratum with sign-flip (tests SignalPurity theorem lower bound), Type-D with zero CorrectedGap, collider with manifest flip (tests collider no-manifest theorem). Register H-synthetic-edge-coverage (all 4 theorem boundary regions covered by ≥1 synthetic study).', 'The four corpus theorems were witnessed on real-data studies with natural variation. Do synthetic edge-case studies at the exact geometric boundaries confirm the theorems hold — or reveal undiscovered corner-case violations?', 'Pending — current 5 synthetic studies (loops 7, 14, 19, 50) were designed for illustration, not theorem boundary stress-testing.', 'loop-92: allocation-corrected winner stability — cross-study meta-theorem', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-92', 'Allocation-corrected winner stability — cross-study meta-theorem', 'planned', 'CorrectedWinnerStability table (one row per Studies.Domain aggregating CorrectedPolicyImplication agreement rate across studies in domain); register H-corrected-winner-stable-across-types (CorrectedGap winner agrees with per-stratum winner in ≥90% of studies for all DistortionTypes including C+/C−); promote conc-36: allocation correction recovers ground truth even when pooled signal inverts.', 'Across 238 studies and all five distortion types, does the allocation-corrected treatment winner (from CorrectedPolicyImplication) consistently match the per-stratum unanimous winner — establishing CorrectedGap as a reliable recovery instrument, not merely a theoretical construct?', 'Pending — CorrectedPolicyImplication computed for all studies post-loop-28; corpus-wide agreement rate not yet aggregated into a first-class entity.', 'loop-93: temporal meta-analysis — does paradox geometry shift over publication decades?', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-93', 'Temporal meta-analysis — paradox geometry shift across publication decades', 'planned', 'DecadeSummary table (one row per publication decade 1950s–2020s from Studies.PublicationYear); fields: StudyCount, ManifestFlipRate, LatentFlipRate, TypeDFraction, AvgAllocationDistortion, DominantIdentity; register H-temporal-allocation-distortion-growth (AvgAllocationDistortion in 2000s–2020s > 1970s–1990s, reflecting larger multi-arm clinical trials); H-temporal-latent-growth (LatentFlipRate higher in recent decades as causal inference awareness increases).', 'Does the 238-study corpus, spanning ~70 years of published research, show systematic change in Simpson''s Paradox geometry over time — specifically, are more recent studies exhibiting higher allocation distortion (larger multi-arm RCTs) and higher latent-flip rates (post-causal-inference-awareness reporting)?', 'Pending — Studies.PublicationYear populated from loop-47; DecadeSummary not yet a first-class entity. PublicationYear range in corpus: 1946–2023.', 'loop-94: confounder identity × temporal interaction — which archetypes are rising vs declining?', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-94', 'Identity × temporal interaction — rising vs declining confounder archetypes by decade', 'planned', 'IdentityDecadeCells table (ConfounderIdentity × decade with n≥2); fields: StudyCount, ManifestFlipRate, TypeDFraction; register H-age-composition-declining (age-composition studies concentrated pre-2000, fewer post-2010 as age-adjustment becomes standard); H-selection-frailty-rising (selection-frailty concentrated in post-2000 clinical trials as frailty indices adopted); promote conc-37: some confounder archetypes are era-specific artifacts of methodological norms.', 'Are certain confounder archetypes (age-composition, disease-severity) artifacts of pre-causal-inference methodological norms — concentrated in older studies — while others (selection-frailty, treatment-indication) are products of modern complex-trial design concentrated in recent decades?', 'Pending — depends on DecadeSummary (loop-93) and IdentityDomainCells (loop-82/86). IdentityDecadeCells is a new entity.', 'loop-95: meta-synthesis — corpus portrait + theorem portfolio as first-class CorpusNarrative entity', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-95', 'Meta-synthesis — CorpusNarrative entity + theorem portfolio as first-class witnesses', 'planned', 'CorpusNarrative table (singleton row) with calculated fields: TotalStudyCount, ManifestFlipRate, LatentFlipRate, TypeDFraction, TheoremCount, IdentityCount, DomainCount, DominantConfounderIdentity, EraSpanYears, CorrectedWinnerAgreementRate, NarrativeSummary (CONCAT of key metrics into publishable abstract sentence); Conclusions conc-38 corpus self-portrait; __meta__ tagline update to reflect loop-95 maturity.', 'Can the instrument describe itself — producing a publishable one-paragraph corpus portrait from DAG-computed metrics alone, with no hand-authored summary — demonstrating that the rulebook''s derived geometry is complete enough to narrate its own findings?', 'Pending — NarrativeSummary is the first CONCAT-formula field in the corpus that produces natural-language prose from numeric witnesses. Singleton CorpusNarrative table mirrors __meta__ but is domain-data not project-metadata.', 'loop-96: peer-review readiness audit — invariant tightening + open-questions registry', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

INSERT INTO loops (loop_id, title, status, new_concept, domain_question, mock_data_note, next_suggestion, tradition_id, commit_hash, commit_date, commit_message, git_tag)
VALUES ('loop-96', 'Peer-review readiness audit — invariant tightening + open-questions registry', 'planned', 'OpenQuestions table (pre-registered limitations and scope boundaries: causal graph not encoded, publication bias not modeled, RCT vs observational not formally distinguished, ALLHAT and 3 clinical-trial REAL? studies pending); tighten InvariantChecks to promote any current warning-severity checks with FailCount=0 to critical; register H-invariant-completeness (all 29 critical invariants pass at N=238); final Rulespeak export covering all 96 loops; tag corpus as methods-paper-ready in __meta__.', 'After 96 loops, 238 studies, 5 theorems, 15 confounder archetypes, and a temporal meta-layer, what are the instrument''s documented limitations — and are they registered as first-class data rather than prose caveats — making the instrument honest about its own scope boundaries?', 'Pending — OpenQuestions is a new table modeling known unknowns as corpus data. Final invariant tightening depends on loops 82–95 all passing with FailCount=0 on their newly registered invariants.', 'Submit methods paper. Begin domain-specific deep-dive series (e.g., loop-97: medicine-only sub-corpus analysis at N=34).', 'tradition-dag', NULL, NULL, NULL, NULL) ON CONFLICT (loop_id) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, new_concept = EXCLUDED.new_concept, domain_question = EXCLUDED.domain_question, mock_data_note = EXCLUDED.mock_data_note, next_suggestion = EXCLUDED.next_suggestion, tradition_id = EXCLUDED.tradition_id, commit_hash = EXCLUDED.commit_hash, commit_date = EXCLUDED.commit_date, commit_message = EXCLUDED.commit_message, git_tag = EXCLUDED.git_tag;

