VALUES ('acharya-imbierowicz-steffen-teichmann-2020-B', 'acharya-imbierowicz-steffen-teichmann-2020', 'B', 'Treatment B (reference comparison arm).') ON CONFLICT (treatment_id) DO UPDATE SET study = EXCLUDED.study, treatment_label = EXCLUDED.treatment_label, description = EXCLUDED.description;

-- ----------------------------------------------------------------------------
-- Strata: Table: Strata — the subdivisions of patients within a study by the value of the confounding variable (e.g. stone size). Each stratum belongs to one study.
-- ----------------------------------------------------------------------------
INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-1986-small', 'kidney-1986', 'small', 'Patients with small kidney stones — easier to treat, higher baseline success rate regardless of treatment.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-1986-large', 'kidney-1986', 'large', 'Patients with large kidney stones — harder to treat, lower baseline success rate regardless of treatment. Preferentially assigned to Treatment A.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-balanced-small', 'kidney-balanced', 'small', 'Small kidney stones — same baseline rates as kidney-1986 small stratum but now receiving exactly 50% of each treatment''s cases. Counterfactual stratum.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('kidney-balanced-large', 'kidney-balanced', 'large', 'Large kidney stones — same baseline rates as kidney-1986 large stratum but now receiving exactly 50% of each treatment''s cases. Equal allocation prevents confounding.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('balanced-synthetic-easy', 'balanced-synthetic', 'easy', 'Easy stratum — higher baseline success rate. Receives exactly 50% of each treatment''s cases.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('balanced-synthetic-hard', 'balanced-synthetic', 'hard', 'Hard stratum — lower baseline success rate. Receives exactly 50% of each treatment''s cases. Equal allocation prevents confounding.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('berkeley-1973-dept-A', 'berkeley-1973', 'dept-A', 'Dept A — highly competitive (low admission rate ~64%). Women applied here at roughly equal rates to men.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('berkeley-1973-dept-B', 'berkeley-1973', 'dept-B', 'Dept B — competitive (~35% admission). Women applied here less often.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('berkeley-1973-dept-C', 'berkeley-1973', 'dept-C', 'Dept C — moderately selective (~34% admission). More balanced gender application.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('berkeley-1973-dept-D', 'berkeley-1973', 'dept-D', 'Dept D — open (~64% admission). Women applied here most heavily — this is the easy department that women disproportionately chose.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('compressed-synthetic-hard', 'compressed-synthetic', 'hard', 'Hard stratum — lower baseline success rates (A=70%, B=60%). Treatment A is over-allocated here (60% of A cases vs 40% of B cases). This is the stratum that pulls A''s pooled rate down relative to equal-weight expectation.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('compressed-synthetic-easy', 'compressed-synthetic', 'easy', 'Easy stratum — higher baseline success rates (A=90%, B=80%). Treatment B is over-allocated here (60% of B cases vs 40% of A cases). This partially offsets B''s per-stratum disadvantage in the pooled analysis.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('reintjes-2000-low', 'reintjes-2000', 'low', 'Low-incidence hospitals (baseline UTI rate ≤2.5%). Prophylaxis rate: 20/1113=1.80%. Control rate: 5/720=0.69%. Prophylaxis is harmful here. Most prophylaxis patients land in this stratum (87%), pulling the aggregate prophylaxis rate down and fabricating an apparent protective effect pooled.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('reintjes-2000-high', 'reintjes-2000', 'high', 'High-incidence hospitals (baseline UTI rate >2.5%). Prophylaxis rate: 22/166=13.25%. Control rate: 99/1520=6.51%. Prophylaxis is again harmful. Controls are heavily concentrated here (1520 of 2240=68%), inflating the aggregate control rate.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('radelet-1981-white-victim', 'radelet-1981', 'white-victim', 'Cases with a white victim. Death penalty issued far more often here (~17% pooled). White def: 19/151=12.58%. Black def: 11/63=17.46%. Black defendants MORE likely within this stratum.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('radelet-1981-black-victim', 'radelet-1981', 'black-victim', 'Cases with a black victim. Death penalty rare here (~3.3% pooled). White def: 0/9=0.00%. Black def: 6/103=5.83%. Black defendants STILL more likely. Most black defendants are in this low-rate stratum (103/166=62%), dragging their aggregate rate down.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('jeter-justice-1997-1995', 'jeter-justice-1997', '1995', '1995 season. Jeter: 12/48=.250. Justice: 104/411=.253. Justice wins by 3 points. Small season for Jeter (48 AB, rookie call-up); Justice''s heaviest season (411 AB) and his weakest average — this is the stratum doing the most damage to Justice''s combined rate.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('jeter-justice-1997-1996', 'jeter-justice-1997', '1996', '1996 season. Jeter: 183/582=.314. Justice: 45/140=.321. Justice wins by 7 points. Jeter''s breakout full season (582 AB). Justice had a shortened season (140 AB) but a high average — a small, strong stratum that lifts his per-year record but contributes little weight to combined.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('jeter-justice-1997-1997', 'jeter-justice-1997', '1997', '1997 season. Jeter: 190/654=.291. Justice: 163/495=.329. Justice wins by 38 points — the largest per-stratum gap. Jeter''s largest season (654 AB). The allocation imbalance is clear: Jeter has 654 AB in a .291 year vs Justice''s 495 at .329.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('appleton-1996-18-24', 'appleton-1996', '18-24', 'Age 18-24 at baseline. Smokers: 2/55=3.6% mortality. Non-smokers: 1/72=1.4%. Smokers worse. Very low mortality overall; small absolute differences.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('appleton-1996-25-34', 'appleton-1996', '25-34', 'Age 25-34 at baseline. Smokers: 3/125=2.4% mortality. Non-smokers: 4/156=2.6%. Effectively tied (smokers marginally better — near-zero stratum gap). Very low mortality stratum.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('appleton-1996-35-44', 'appleton-1996', '35-44', 'Age 35-44 at baseline. Smokers: 10/105=9.5% mortality. Non-smokers: 7/111=6.3%. Smokers clearly worse.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('appleton-1996-45-54', 'appleton-1996', '45-54', 'Age 45-54 at baseline. Smokers: 28/131=21.4% mortality. Non-smokers: 12/78=15.4%. Smokers worse; gap widening with age.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('appleton-1996-55-64', 'appleton-1996', '55-64', 'Age 55-64 at baseline. Smokers: 52/116=44.8% mortality. Non-smokers: 41/122=33.6%. Smokers clearly worse; largest absolute gap in the middle strata.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('appleton-1996-65-74', 'appleton-1996', '65-74', 'Age 65-74 at baseline. Smokers: 31/37=83.8% mortality. Non-smokers: 101/129=78.3%. Smokers worse. Small smoker group (37) — most heavy smokers in this cohort had already died before reaching 65 at baseline (survivorship selection).') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('appleton-1996-75plus', 'appleton-1996', '75+', 'Age 75+ at baseline. Smokers: 13/13=100% mortality. Non-smokers: 64/64=100%. Both groups reach 100% at 20-year follow-up — everyone in this stratum died. StratumGap=0. Heavy survivorship selection: only 13 smokers survived to 75+ at baseline vs 64 non-smokers.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('phe-covid-2021-under-50', 'phe-covid-2021', 'under 50', 'Age under 50. Vaccinated CFR: 21/89,807=0.023%. Unvaccinated CFR: 48/147,612=0.033%. Vaccinated clearly better. Low absolute mortality in both groups — under-50 COVID Delta deaths are rare regardless of vaccination status.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('phe-covid-2021-50plus', 'phe-covid-2021', '50 +', 'Age 50 and over. Vaccinated CFR: 460/27,307=1.68%. Unvaccinated CFR: 205/3,440=5.96%. Vaccinated dramatically better (3.5× lower death rate). The enormous relative risk reduction in this high-mortality stratum is the true vaccine signal — but it is hidden in the pooled comparison because so few unvaccinated people are in this stratum (3,440 vs 27,307 vaccinated).') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('hannan-1994-high-risk', 'hannan-1994', 'high-risk', 'High-risk CABG patients (EuroSCORE-equivalent ≥5). High-volume hospitals (A) are heavily loaded with these cases — 70% of A''s caseload is high-risk vs only 20% of B''s. A wins this stratum (95.0% vs 80.0%, a 15pp advantage). The over-representation of hard cases in A drags A''s pooled rate down relative to the equal-weight benchmark.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('hannan-1994-low-risk', 'hannan-1994', 'low-risk', 'Low-risk CABG patients (EuroSCORE-equivalent <5). Low-volume hospitals (B) have disproportionately more easy cases — 80% of B''s caseload vs only 30% of A''s. A still wins this stratum (99.0% vs 96.9%, a 2pp advantage). The allocation imbalance compresses A''s pooled advantage from 7.9pp (equal-weight) down to 2.8pp (actual pooled) without reversing it — the fingerprint of type-C distortion.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('titanic-1912-male', 'titanic-1912', 'male', 'Male passengers. 1st class (A): 57/175=32.6% survived. 3rd class (B): 75/462=16.2% survived. 1st class wins. Males are over-represented in 3rd class (462 vs 175) and in 3rd class the per-sex advantage for 1st class is modest. This stratum has the most cases and contributes heavily to the pooled comparison.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('titanic-1912-female', 'titanic-1912', 'female', 'Female passengers. 1st class (A): 139/144=96.5% survived. 3rd class (B): 76/165=46.1% survived. 1st class wins by 50.4pp — the largest per-stratum gap. 1st class has a higher fraction of women (144/319=45%) than 3rd class (165/627=26%). This over-representation of women in 1st class inflates the pooled 1st-class survival rate beyond the equal-weight per-stratum average — the allocation distortion inflates rather than compresses the advantage.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('bwp-lbw', 'birth-weight-paradox', 'low-birth-weight', 'Low birth weight babies (<2500g). Smoker infants (A): 960/1000=96.0% survival. Non-smoker infants (B): 470/500=94.0% survival. Smokers win this stratum. The mechanism (Hernandez-Diaz 2006): low birth weight among non-smokers is more likely caused by serious congenital anomalies or pathologies, whereas smoking-related low birth weight is a ''milder'' cause — so the surviving non-smoker LBW infants are a sicker selected group. Smokers are over-represented in this stratum (1000 vs 500 babies).') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('bwp-nbw', 'birth-weight-paradox', 'normal-birth-weight', 'Normal birth weight babies (≥2500g). Smoker infants (A): 995/1000=99.5% survival. Non-smoker infants (B): 4980/5000=99.6% survival. Non-smokers barely win (0.1pp). Non-smokers vastly outnumber smokers here (5000 vs 1000). Pooled, non-smokers (B) win because this stratum dominates B''s total, and B wins it. The pooled result reverses the LBW stratum finding — a partial (type-B) paradox driven by the LBW vs NBW allocation imbalance.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('mel-thin', 'melanoma-altman-1991', 'thin', 'Thin melanoma tumors (<1mm Breslow depth). Female patients (A): 133/140=95.0% 10-year survival. Male patients (B): 70/80=87.5% survival. Females win by 7.5pp. Women present with thin tumors more often (140/200=70% of female cases are thin vs 80/200=40% of male cases) — reflecting earlier detection and help-seeking behavior.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('mel-thick', 'melanoma-altman-1991', 'thick', 'Thick melanoma tumors (≥1mm Breslow depth). Female patients (A): 39/60=65.0% 10-year survival. Male patients (B): 66/120=55.0% survival. Females win by 10pp. Males are over-represented here (120/200=60% of male cases are thick vs 60/200=30% of female cases). Women''s disproportionate concentration in the high-survival thin-tumor stratum inflates the pooled female advantage beyond the equal-weight per-stratum average.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('coffee-nonsmoker', 'coffee-tverdal-2020', 'non-smoker', 'Never- or ex-smokers. Coffee drinkers (A): 920/1000=92.0% CHD-free at 10 years. Non-drinkers (B): 890/1000=89.0%. Coffee wins by 3pp. Equal allocation (1000 each treatment). No allocation imbalance — the per-stratum result passes through to the pooled result unchanged.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('coffee-smoker', 'coffee-tverdal-2020', 'smoker', 'Current smokers. Coffee drinkers (A): 820/1000=82.0% CHD-free. Non-drinkers (B): 800/1000=80.0%. Coffee wins by 2pp. Equal allocation. Smoking increases baseline CHD risk in both groups but does not confound the coffee comparison because allocation is balanced. This study is type-D: genuine benefit of coffee, no distortion by allocation.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('sat-lowspend', 'sat-wainer-1986', 'low-spending', 'Low-spending states (<$3000 per pupil, 1986 dollars). High-participation states (A): 240/600=40.0% scored ≥500. Low-participation states (B): 35/100=35.0% scored ≥500. A wins by 5pp. High-participation states dominate this stratum (600 vs 100 students in sample), sending more students including weaker ones.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('sat-highspend', 'sat-wainer-1986', 'high-spending', 'High-spending states (≥$3000 per pupil, 1986 dollars). High-participation states (A): 280/400=70.0% scored ≥500. Low-participation states (B): 40/50=80.0% scored ≥500. B wins by 10pp — in well-funded states, the small self-selected group of test-takers in low-participation states scores higher because they are disproportionately college-bound high-achievers. This stratum reversal drives the pooled paradox (type-B): A wins low-spending stratum, B wins high-spending, B slightly leads pooled.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('rogers-nicewander-1988-infield-proxy', 'rogers-nicewander-1988', 'infield-proxy', 'World Series 1 (proxy stratum). Fairly 11/29=.379; Lefebvre 4/10=.400. Lefebvre wins.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

INSERT INTO strata (stratum_id, study, stratum_label, description)
VALUES ('rogers-nicewander-1988-outfield-proxy', 'rogers-nicewander-1988', 'outfield-proxy', 'World Series 2 (proxy stratum). Fairly 1/7=.143; Lefebvre 2/12=.167. Lefebvre wins.') ON CONFLICT (stratum_id) DO UPDATE SET study = EXCLUDED.study, stratum_label = EXCLUDED.stratum_label, description = EXCLUDED.description;

