-- ----------------------------------------------------------------------------
-- ModelSummary: Table: ModelSummary — one row describing the epistemic coverage of this entire model instance. Aggregates across all TreatmentRankings to witness how many studies were examined, how many showed a full reversal, how many were explained, and the average paradox strength. The model holds a mirror to itself.
-- ----------------------------------------------------------------------------
INSERT INTO model_summary (model_summary_id, real_study_count, avg_signal_purity_reversal, avg_signal_purity_non_reversal, signal_purity_gap, medicine_study_count, epidemiology_study_count, other_domain_study_count, domain_diversity_note, synthetic_phase_count, phase_diagram_complete, phase_taxonomy_coverage, high_imbalance_sign_flip_threshold, economics_high_imbalance_sign_flip_count, epidemiology_high_imbalance_sign_flip_rate, legal_high_imbalance_sign_flip_rate, sports_high_imbalance_sign_flip_rate, identity_cluster_witness_note)
VALUES ('simpsons-paradox-v1', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (model_summary_id) DO UPDATE SET real_study_count = EXCLUDED.real_study_count, avg_signal_purity_reversal = EXCLUDED.avg_signal_purity_reversal, avg_signal_purity_non_reversal = EXCLUDED.avg_signal_purity_non_reversal, signal_purity_gap = EXCLUDED.signal_purity_gap, medicine_study_count = EXCLUDED.medicine_study_count, epidemiology_study_count = EXCLUDED.epidemiology_study_count, other_domain_study_count = EXCLUDED.other_domain_study_count, domain_diversity_note = EXCLUDED.domain_diversity_note, synthetic_phase_count = EXCLUDED.synthetic_phase_count, phase_diagram_complete = EXCLUDED.phase_diagram_complete, phase_taxonomy_coverage = EXCLUDED.phase_taxonomy_coverage, high_imbalance_sign_flip_threshold = EXCLUDED.high_imbalance_sign_flip_threshold, economics_high_imbalance_sign_flip_count = EXCLUDED.economics_high_imbalance_sign_flip_count, epidemiology_high_imbalance_sign_flip_rate = EXCLUDED.epidemiology_high_imbalance_sign_flip_rate, legal_high_imbalance_sign_flip_rate = EXCLUDED.legal_high_imbalance_sign_flip_rate, sports_high_imbalance_sign_flip_rate = EXCLUDED.sports_high_imbalance_sign_flip_rate, identity_cluster_witness_note = EXCLUDED.identity_cluster_witness_note;

-- ----------------------------------------------------------------------------
-- StratumVariables: Table: StratumVariables — one row per study, naming the variable that defines the strata and describing its causal role. A confounder affects both treatment assignment AND outcome; a mediator is downstream of treatment; a contested variable is one where the causal role is disputed. IsConfounder is derived from these two boolean flags.
-- ----------------------------------------------------------------------------
INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('kidney-1986-stone-size', 'kidney-1986', 'stone_size', 'confounder', TRUE, TRUE, 'Large kidney stones were preferentially assigned to Treatment A (the more aggressive procedure), while small stones more often received Treatment B. Independently, large stones have lower baseline cure rates regardless of treatment. This dual influence — on both assignment and on outcome — is what drives the pooled reversal.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('berkeley-1973-department', 'berkeley-1973', 'department', 'contested', TRUE, TRUE, 'Department choice correlates with both gender (women applied disproportionately to competitive departments) and admission rate (competitive departments admit fewer applicants regardless of gender). However, department choice may itself be downstream of gender — if women systematically self-select into harder departments due to societal factors, then department is a mediator, not a confounder. The causal role is genuinely contested in the literature. IsConfounder=FALSE because CausalRole=''contested'', not because the flags are false.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('kidney-balanced-stone-size', 'kidney-balanced', 'stone_size', 'confounder', FALSE, TRUE, 'In this counterfactual, stone size still affects outcome (hard cases have lower success rates) but does NOT affect treatment assignment — both treatments receive exactly 50% of their cases in each stratum. Because treatment assignment is now independent of stone size, no confounding occurs and AllocationBias=0 everywhere. IsConfounder=FALSE (AffectsTreatmentAssignment=false). The reversal is impossible by construction.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('balanced-synthetic-stratum', 'balanced-synthetic', 'stratum', 'unknown', FALSE, TRUE, 'The stratum variable affects outcome (easy vs hard conditions) but does NOT affect treatment assignment — each treatment receives exactly 50% of its cases in each stratum. Because treatment assignment is independent of stratum, no confounding can occur and the pooled rate must agree with every per-stratum comparison.', 'none') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('compressed-synthetic-stratum', 'compressed-synthetic', 'difficulty', 'confounder', TRUE, TRUE, 'Case difficulty affects both which treatment patients receive (A is over-allocated to hard cases: 60% vs 40%) and the outcome (hard cases have lower success rates for both treatments). This IS confounding — but the confounding is not strong enough to flip the pooled winner. A wins in every stratum and also wins pooled. The allocation compresses A''s pooled advantage (from equal-weight 10pp down to actual 6pp) but does not erase it. This is type-C distortion: real confounding, partial distortion, no reversal.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('reintjes-2000-hospital-incidence', 'reintjes-2000', 'hospital_incidence_level', 'confounder', TRUE, TRUE, 'Hospital baseline UTI incidence affects both whether a patient received prophylaxis (high-incidence hospitals were more likely to forgo it, concentrating controls there) and the outcome (high-incidence hospitals have higher UTI rates regardless of treatment). Most prophylaxis patients are in low-incidence hospitals (1113/1279=87%), which depresses the aggregate prophylaxis UTI rate below the aggregate control rate — inverting the within-stratum finding.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('radelet-1981-victim-race', 'radelet-1981', 'victim_race', 'confounder', TRUE, TRUE, 'Victim race affects both defendant race (cross-race homicides are rare — most black defendants killed black victims, most white defendants killed white victims) and sentencing outcome (white-victim cases receive the death penalty ~5× more often: ~17.7% vs ~3.3%). This is classic confounding. Black defendants are disproportionately concentrated in the black-victim stratum (low sentence rate), pulling their aggregate death penalty rate below white defendants'' rate — even though black defendants are MORE likely to be sentenced to death within each victim-race stratum.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('jeter-justice-1997-season', 'jeter-justice-1997', 'season_year', 'confounder', TRUE, TRUE, 'The season year affects both the player''s at-bat count (treatment assignment proxy — Justice''s heaviest season was 1995 when his average was lowest; Jeter''s heaviest were 1996-97 when his average was higher) and the outcome (players hit differently in different years). Justice front-loaded his ABs into his worst year (411 of 1046 = 39% in 1995 at .253); Jeter back-loaded into his stronger years (1236 of 1284 = 96% in 1996-97 at .300-.314). This differential allocation of AB-weight across years flips the combined average despite Justice winning every year individually.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('appleton-1996-age', 'appleton-1996', 'age_group_at_baseline', 'confounder', TRUE, TRUE, 'Age at baseline confounds both smoking status and 20-year mortality. Smoking affects age distribution in the cohort (survivorship bias: people who smoked heavily and were older had already died before the 1972-74 baseline survey, so the surviving smokers skew younger). Age strongly determines 20-year mortality regardless of smoking. The result: smokers are over-represented in low-mortality age strata (18-44), pulling the pooled smoker mortality rate below the true within-stratum risk. This is the textbook epidemiological confounding by age pattern, often called the "healthy smoker" fallacy in this particular dataset.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('phe-covid-2021-age', 'phe-covid-2021', 'age_group', 'confounder', TRUE, TRUE, 'Age group is a powerful confounder. It affects vaccine uptake (older people were prioritised and had much higher vaccination rates in the UK''s 2021 rollout — 23% of vaccinated are 50+ vs only 2.3% of unvaccinated) and strongly determines COVID-19 mortality (50+ CFR is ~40× higher than under-50 CFR in this dataset regardless of vaccination). The vaccinated cohort is therefore loaded with high-risk patients, inflating the pooled vaccinated death rate to 0.41% vs 0.17% for unvaccinated — reversing the within-stratum relationship where vaccines reduce death rates by 3× to 4× in every age group.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('hannan-1994-patient-risk', 'hannan-1994', 'patient_risk_class', 'confounder', TRUE, TRUE, 'Patient risk class affects both hospital assignment (high-volume centers receive referrals of sicker patients — 70% of A caseload is high-risk vs only 20% at B) and surgical outcome (high-risk patients have dramatically higher operative mortality regardless of hospital volume). High-volume hospitals win in every risk stratum (15pp advantage in high-risk, 2pp in low-risk) and also win pooled — but their pooled survival advantage is compressed from 7.9pp (equal-weight stratum average) down to 2.8pp (actual pooled) because they carry so many harder cases. IsSignFlip=FALSE, AllocationDistortion≈0.05 — the geometry of type-C distortion: real confounding, partial distortion, no reversal.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('titanic-1912-sex', 'titanic-1912', 'passenger_sex', 'confounder', TRUE, TRUE, 'Passenger sex affects both cabin class (1st class had a higher fraction of women — 45% vs 26% in 3rd class, reflecting social travel patterns of the era) and survival outcome (''women and children first'' evacuation protocol gave women dramatically higher survival rates regardless of class). The over-representation of women in 1st class inflates the pooled 1st-class survival advantage beyond the per-stratum (per-sex) average — the pooled gap (37.4pp) exceeds the equal-weight average (33.4pp). AllocationDistortion>0, IsSignFlip=FALSE → type-C.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('bwp-weight-class', 'birth-weight-paradox', 'birth_weight_category', 'mediator', TRUE, TRUE, 'Birth weight category is a mediator, not a classical confounder — it lies on the causal pathway from maternal smoking to infant mortality (smoking causes low birth weight, which causes elevated mortality). Conditioning on birth weight (stratifying) opens a collider path: among LBW infants, smoker babies are ''selected in'' via a milder mechanism (growth restriction) while non-smoker LBW babies are more likely to have serious congenital causes. This creates the paradox: smokers appear to have better LBW survival not because smoking is protective, but because the comparison groups differ in unobserved severity. IsSignFlip=TRUE, RI=0.5 → type-B (partial reversal: smokers win LBW stratum, non-smokers win NBW, non-smokers win pooled).', 'mediator') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('melanoma-sex', 'melanoma-altman-1991', 'patient_sex', 'confounder', TRUE, TRUE, 'Patient sex affects both tumor thickness at presentation (women self-examine and seek medical attention earlier — 70% of female melanomas are thin vs 40% of male melanomas) and survival outcome (beyond the thickness effect, female sex is an independent prognostic factor for melanoma). Women''s concentration in the high-survival thin-tumor stratum inflates their pooled survival advantage from 7.9pp (equal-weight per-stratum average) to 18pp (actual pooled). IsSignFlip=FALSE, AllocationDistortion=0.094 → type-C inflation.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('coffee-smoking', 'coffee-tverdal-2020', 'smoking_status', 'confounder', FALSE, TRUE, 'Smoking status affects CHD outcome (smokers have higher baseline CHD risk) but does NOT materially affect coffee consumption (equal allocation across strata in this study design). Because treatment assignment is effectively independent of the confounder, no allocation imbalance occurs and the pooled estimate agrees with the per-stratum estimates. AllocationDistortion≈0 → type-D: no Simpson distortion. This study is the clean null case — confounders that do not create allocation imbalance do not distort the pooled result.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('sat-school-spending', 'sat-wainer-1986', 'state_school_spending', 'confounder', TRUE, TRUE, 'State school spending confounds the participation-rate / SAT-score comparison. High-spending states tend to have high participation (more students take the SAT, including weaker students), and high spending is independently associated with better educational outcomes. Within each spending stratum, high-participation states do better (or tie), because controlling for spending removes the quality signal. But in high-spending states, the small self-selected pool of test-takers from low-participation states outscores the broad pool from high-participation states — reversing the low-spending stratum winner. IsSignFlip=TRUE, RI=0.5 → type-B partial reversal.', 'proxy') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
VALUES ('rogers-nicewander-1988-position_group', 'rogers-nicewander-1988', 'position_group', 'confounder', TRUE, TRUE, 'Series stratum affects both at-bat allocation (Fairly had 36 AB combined vs Lefebvre 22) and batting average. Fairly wins each series individually but loses combined — classic type-A reversal via differential AB weighting.', 'confounder') ON CONFLICT (stratum_variable_id) DO UPDATE SET study = EXCLUDED.study, variable_name = EXCLUDED.variable_name, causal_role = EXCLUDED.causal_role, affects_treatment_assignment = EXCLUDED.affects_treatment_assignment, affects_outcome = EXCLUDED.affects_outcome, mechanism_note = EXCLUDED.mechanism_note, conditioning_risk = EXCLUDED.conditioning_risk;

INSERT INTO stratum_variables (stratum_variable_id, study, variable_name, causal_role, affects_treatment_assignment, affects_outcome, mechanism_note, conditioning_risk)
