VALUES ('inv-type-d-ratio-near-unity', 'DistortionType = D → ABS(DistortionRatio - 1) < 0.15 OR |CorrectedGap| < 0.02', 'Type-D studies have ratio near 1 when signal exists; degenerate near-zero gaps may yield ratio far from 1 or NULL.', 'TreatmentRankings', 'DistortionType = ''D''', 'ABS(DistortionRatio - 1) < 0.15 OR ABS(CorrectedGap) < 0.02 OR DistortionRatio IS NULL', 'distortion_type = ''D''', 'ABS(distortion_ratio - 1) < 0.15 OR ABS(corrected_gap) < 0.02 OR distortion_ratio IS NULL', 34, 0, 'critical', 'tradition-historical', 'conc-02-reversal-from-allocation') ON CONFLICT (invariant_check_id) DO UPDATE SET algebraic_statement = EXCLUDED.algebraic_statement, natural_language = EXCLUDED.natural_language, source_table = EXCLUDED.source_table, filter_expression = EXCLUDED.filter_expression, assertion_expression = EXCLUDED.assertion_expression, sql_filter = EXCLUDED.sql_filter, sql_assertion = EXCLUDED.sql_assertion, pass_count = EXCLUDED.pass_count, fail_count = EXCLUDED.fail_count, severity = EXCLUDED.severity, tradition_id = EXCLUDED.tradition_id, protects_conclusion = EXCLUDED.protects_conclusion;

