VALUES ('inv-theorem-consistency-confirmed', 'COUNTIFS(DiscoveryFindings IsConfirmed FALSE WHERE EpistemicTier=consistency-check AND RegisteredInLoop IN loop-73..76) = 0', 'Theorem wave + identity consistency checks: CorrectedGap invariance, explained↔confounder biconditional, collider no-manifest, theorem portfolio, identity map coverage, unexplained-sink identity law.', 'DiscoveryFindings', 'HypothesisEpistemicTier = consistency-check', 'IsConfirmed = TRUE', 'hypothesis_id IN (''H-corrected-gap-invariant'', ''H-explained-bidirectional'', ''H-collider-no-manifest-theorem'', ''H-theorem-portfolio'', ''H-identity-map-coverage'', ''H-unexplained-flips-only-nonconfounders'')', 'is_confirmed = TRUE', 6, 0, 'critical', 'tradition-dag', 'conc-31-theorem-portfolio-synthesis') ON CONFLICT (invariant_check_id) DO UPDATE SET algebraic_statement = EXCLUDED.algebraic_statement, natural_language = EXCLUDED.natural_language, source_table = EXCLUDED.source_table, filter_expression = EXCLUDED.filter_expression, assertion_expression = EXCLUDED.assertion_expression, sql_filter = EXCLUDED.sql_filter, sql_assertion = EXCLUDED.sql_assertion, pass_count = EXCLUDED.pass_count, fail_count = EXCLUDED.fail_count, severity = EXCLUDED.severity, tradition_id = EXCLUDED.tradition_id, protects_conclusion = EXCLUDED.protects_conclusion;

