VALUES ('inv-confounder-signflip-explained', 'IsSignFlip=TRUE AND StratumCausalRole=''confounder'' → IsParadoxExplained=TRUE', 'Every confounder manifest sign-flip must be marked explained. Other half of the explained↔confounder biconditional (loop-74).', 'TreatmentRankings', 'IsSignFlip = TRUE AND StratumCausalRole = ''confounder''', 'IsParadoxExplained = TRUE', 'is_sign_flip = true AND stratum_causal_role = ''confounder''', 'is_paradox_explained = true', 0, 0, 'critical', 'tradition-dag', 'conc-29-explained-confounder-theorem') ON CONFLICT (invariant_check_id) DO UPDATE SET algebraic_statement = EXCLUDED.algebraic_statement, natural_language = EXCLUDED.natural_language, source_table = EXCLUDED.source_table, filter_expression = EXCLUDED.filter_expression, assertion_expression = EXCLUDED.assertion_expression, sql_filter = EXCLUDED.sql_filter, sql_assertion = EXCLUDED.sql_assertion, pass_count = EXCLUDED.pass_count, fail_count = EXCLUDED.fail_count, severity = EXCLUDED.severity, tradition_id = EXCLUDED.tradition_id, protects_conclusion = EXCLUDED.protects_conclusion;

