VALUES ('inv-collider-no-manifest', 'StratumCausalRole ∈ {collider, selection} → IsSignFlip = FALSE', 'Collider and selection studies never produce manifest sign-flips at observed allocation — conditional theorem requiring correct causal-role annotation (loop-75).', 'TreatmentRankings', 'StratumCausalRole IN (''collider'',''selection'')', 'IsSignFlip = FALSE', 'stratum_causal_role IN (''collider'', ''selection'')', '(is_sign_flip = false OR is_sign_flip IS NULL)', 0, 0, 'critical', 'tradition-dag', 'conc-30-collider-no-manifest-theorem') ON CONFLICT (invariant_check_id) DO UPDATE SET algebraic_statement = EXCLUDED.algebraic_statement, natural_language = EXCLUDED.natural_language, source_table = EXCLUDED.source_table, filter_expression = EXCLUDED.filter_expression, assertion_expression = EXCLUDED.assertion_expression, sql_filter = EXCLUDED.sql_filter, sql_assertion = EXCLUDED.sql_assertion, pass_count = EXCLUDED.pass_count, fail_count = EXCLUDED.fail_count, severity = EXCLUDED.severity, tradition_id = EXCLUDED.tradition_id, protects_conclusion = EXCLUDED.protects_conclusion;

