VALUES ('inv-unexplained-identity-sink', 'IsSignFlip=TRUE AND IsParadoxExplained=FALSE → ConfounderIdentity ∈ {id-contested-org-choice, id-collider-proxy}', 'Every unexplained sign-flip must be linked to contested-org-choice or collider-proxy identity — no unexplained flip belongs to an unambiguous confounder archetype. Identity-conditioned extension of conc-29 (loop-74 biconditional).', 'TreatmentRankings', 'IsSignFlip = TRUE AND IsParadoxExplained = FALSE', 'StratumCausalRole IN (''contested'') OR ConfounderIdentity IN (''id-contested-org-choice'',''id-collider-proxy'')', 'is_sign_flip = true AND is_paradox_explained = false', 'stratum_causal_role = ''contested'' OR study IN (
 SELECT s.study_id FROM stratum_variable_identity_maps m
 JOIN stratum_variables sv ON sv.stratum_variable_id = m.stratum_variable
 JOIN studies s ON s.study_id = sv.study
 WHERE m.confounder_identity IN (''id-contested-org-choice'',''id-collider-proxy'')
 )', 3, 0, 'critical', 'tradition-dag', 'conc-35-unexplained-identity-sink-theorem') ON CONFLICT (invariant_check_id) DO UPDATE SET algebraic_statement = EXCLUDED.algebraic_statement, natural_language = EXCLUDED.natural_language, source_table = EXCLUDED.source_table, filter_expression = EXCLUDED.filter_expression, assertion_expression = EXCLUDED.assertion_expression, sql_filter = EXCLUDED.sql_filter, sql_assertion = EXCLUDED.sql_assertion, pass_count = EXCLUDED.pass_count, fail_count = EXCLUDED.fail_count, severity = EXCLUDED.severity, tradition_id = EXCLUDED.tradition_id, protects_conclusion = EXCLUDED.protects_conclusion;

-- ----------------------------------------------------------------------------
-- Methodology: Table: Methodology — the first-principles process used to build this domain model. Each row documents one methodological axiom or step. Together these rows let a reader (or an LLM) reconstruct why the model is shaped the way it is, and re-apply the same process to a new domain.
-- ----------------------------------------------------------------------------
INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-01-cmcc', 'axiom', 'CMCC: any sufficiently crisp conceptual world decomposes into a DAG of S/D/L/A/F primitives', 'The Conceptual Model Conjecture (CMCC) holds that every domain can be decomposed into Schema, Data, Lookups, Aggregations, and Functions arranged as a directed acyclic graph. Each node is locally simple; complexity emerges from composition, not from any single node. This is the working assumption for the entire model, not a hypothesis to relitigate each turn.', 'If CMCC holds, the paradox can be derived rather than modeled. The model does not need a ''ReversalDetection'' entity — it just needs the right leaf data and the right DAG edges. The paradox falls out as a consequence.', 'loop-01', 'tradition-historical', NULL) ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-02-dag-first', 'decomposition', 'Model the domain entities first; derived facts emerge from the DAG', 'Start with the empirical leaf data: Cases and Successes in each (Study, Stratum, Treatment) cell. Never model the phenomenon of interest (the paradox) directly. The paradox is a derived fact — it emerges when you ask the right questions of a correctly-shaped DAG.', 'Modeling the paradox directly (e.g. a ''ReversalDetection'' table) would conflate the phenomenon with the domain. The domain is Studies, Treatments, Strata, and CaseCells. The paradox is a read on that domain.', 'loop-01, loop-04', 'tradition-dag', 'researcher-spirtes-glymour-scheines') ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-03-leopold-loops', 'decomposition', 'Build the model incrementally via Leopold Loops — one new concept per loop', 'Each loop introduces exactly one new first-class concept and asks the natural-language question that concept answers. The loop ends when the new derived fact is witnessed in the database. Loop N''s NextSuggestion seeds Loop N+1.', 'Introducing multiple concepts per loop makes it hard to witness whether each concept earns its place. One concept per loop forces the question: ''what new thing can I now ask that I couldn''t before?''', 'loop-01, loop-02, loop-03, loop-04, loop-05', 'tradition-historical', NULL) ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-04-witness-not-claim', 'derivation', 'Every derived fact must be witnessed from the database, not claimed from the rulebook', 'A field is not ''done'' when it is added to the rulebook. It is done when a Postgres query returns the expected value for the seeded data. MockDataNote in each Loop row states what value is expected and from which study. If the DB returns a different value, the formula or the seed data is wrong.', 'Without witnessing, silent fallbacks and mistranslations accumulate invisibly. The rulebook says CellSuccessRate = Successes/Cases; the DB must actually return 0.931 for kidney small-A.', 'loop-01, loop-06, loop-12, loop-17', 'tradition-dag', 'researcher-spirtes-glymour-scheines') ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-05-synthetic-controls', 'validation', 'Introduce synthetic control studies to test structural impossibility', 'For every interesting derived boolean (IsReversal, IsSignFlip), add at least one synthetic study where the boolean MUST be false by construction. Witnessing the false case in the DB proves the derivation is not vacuously true.', 'Without a structural-impossibility witness, a bug in the formula that always returns TRUE would pass all the positive tests. The balanced-synthetic and kidney-balanced studies exist solely to witness IsReversal=FALSE and AllocationDistortion=0.', 'loop-07, loop-14', 'tradition-epidemiology', 'researcher-greenland') ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-06-real-data-hydration', 'hydration', 'Real study data lives in the rulebook JSON — the SSoT is unified', 'The rulebook JSON is the single source of truth for both schema and instance data. Real published study counts (Successes, Cases per cell) live directly in each table''s data array alongside the synthetic studies. Provenance for each real study is recorded in data/raw/<study-id>/provenance.md. The view chain computes every derived field from the rulebook without any separate hydration step.', 'Keeping schema and instance data together in one document makes the instrument self-contained and auditable. The rulebook JSON can be shared, forked, or loaded without a separate SQL hydration step. The schema still defines derivations; the data rows supply the raw inputs.', 'loop-01, loop-20, loop-20b', 'tradition-epidemiology', 'researcher-robins') ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-07-continuous-geometry', 'taxonomy', 'Replace binary reversal criterion with continuous geometry: IsSignFlip + AllocationDistortion', 'The original IsReversal (unanimous per-stratum winner disagrees with pooled winner) is a binary that excludes partial reversals. The sign-flip definition (WeightedStratumGapSum and SignedPooledGap have opposite signs) captures the full continuum. AllocationDistortion = |WSGSUM − SignedPooledGap| is the scalar severity regardless of direction.', 'Berkeley 1973 fails the unanimity criterion (dept-C gives male a marginal win) but IS a Simpson-type paradox under the continuous definition. Excluding Berkeley from the analysis would be a category error.', 'loop-17, loop-18', 'tradition-historical', 'researcher-blyth') ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-08-four-type-taxonomy', 'taxonomy', 'Classify studies into four types (A/B/C/D) by distortion geometry, independent of causal label', 'Type A = IsSignFlip AND ReversalIntensity=1.0 (full unanimous reversal). Type B = IsSignFlip AND ReversalIntensity<1.0 (partial sign-flip). Type C = NOT IsSignFlip AND AllocationDistortion>threshold (compression without flip). Type D = AllocationDistortion≈0 (neutral). The geometry is computed from allocation and rates alone — no causal story is required.', 'The taxonomy makes PolicyImplication derivable. A researcher reading DistortionType=A knows to stratify immediately without needing to know what caused the allocation imbalance.', 'loop-19, loop-21', 'tradition-historical', 'researcher-blyth') ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-09-model-self-portrait', 'conclusion', 'The model witnesses its own epistemic coverage via ModelSummary', 'ModelSummary is a single-row table that aggregates ReversalCount, ExplainedCount, TypeACount, TypeBCount, TypeCCount, TypeDCount, and AvgAllocationDistortion across all studies. It is the model''s self-portrait — a derived fact about the model''s own completeness.', 'Without ModelSummary, you can query any individual study but cannot ask ''how many studies does this instrument explain?'' The self-portrait is the epistemic coverage claim.', 'loop-10', 'tradition-dag', 'researcher-spirtes-glymour-scheines') ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

INSERT INTO methodology (methodology_id, phase, title, statement, why_it_matters, illustrated_by_loop, tradition_id, pioneering_researcher)
VALUES ('method-10-policy-from-geometry', 'conclusion', 'Policy implication is derived from geometry, not asserted from domain knowledge', 'PolicyImplication is a calculated field derived from DistortionType. No domain-specific knowledge about medicine, law, or education is encoded. The instrument tells a researcher what to do next with the pooled conclusion (stratify, investigate, check bias, or trust) purely from the allocation geometry.', 'Domain-neutral policy derivation means the instrument generalizes across clinical, judicial, educational, and other settings without re-tuning. The same formula works for kidney stones, Berkeley admissions, and antibiotic prophylaxis.', 'loop-21, loop-26', 'tradition-ai-fairness', 'researcher-chouldechova') ON CONFLICT (methodology_id) DO UPDATE SET phase = EXCLUDED.phase, title = EXCLUDED.title, statement = EXCLUDED.statement, why_it_matters = EXCLUDED.why_it_matters, illustrated_by_loop = EXCLUDED.illustrated_by_loop, tradition_id = EXCLUDED.tradition_id, pioneering_researcher = EXCLUDED.pioneering_researcher;

-- ----------------------------------------------------------------------------
-- Conclusions: Table: Conclusions — the substantive epistemic findings that this model has produced or is designed to produce. Each row is one conclusion: a claim about the domain, about the instrument, or about the methodology that is either already witnessed or is the target of a planned loop.
-- ----------------------------------------------------------------------------
INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-01-paradox-is-derived', 'domain', 'witnessed', 'Simpson''s Paradox is a derived fact from the DAG, not a modeled entity', 'IsReversal (and later IsSignFlip) falls out as a calculated field on TreatmentRankings, derived from aggregated CaseCell counts. No ''ReversalDetection'' entity was ever needed.', 'loop-04', NULL, 'tradition-historical', 'researcher-blyth', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-02-reversal-from-allocation', 'domain', 'witnessed', 'The reversal in kidney-1986 is entirely an allocation artifact — same rates with balanced allocation produce no reversal', 'kidney-balanced uses identical stratum success rates to kidney-1986 but with equal allocation (175 cases per cell). IsReversal=FALSE, AllocationDistortion=0. The paradox is algebraically isolated as a property of allocation, not of treatment efficacy.', 'loop-14', NULL, 'tradition-historical', 'researcher-pearson', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-03-binary-excludes-partial', 'instrument', 'witnessed', 'The unanimity criterion (IsReversal) incorrectly excludes Berkeley 1973 despite its being a Simpson-type paradox', 'Berkeley: WSGSUM=−0.0642, SignedPooledGap=+0.1292, IsSignFlip=TRUE, AllocationDistortion=0.1934 — greater distortion than kidney-1986. But IsReversal=FALSE because dept-C marginally favors male. The unanimity criterion is a strict subtype, not the primary definition.', 'loop-17', NULL, 'tradition-historical', 'researcher-blyth', 'researcher-cohen-nagel') ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-04-type-c-exists', 'instrument', 'witnessed', 'Allocation can compress the pooled signal without flipping it (type-C): a class invisible to IsReversal and IsSignFlip but visible to AllocationDistortion', 'compressed-synthetic: A wins every stratum and wins pooled, but the pooled margin is 6pp rather than the equal-weight 10pp. AllocationDistortion=0.0400, IsSignFlip=FALSE. The pooled winner is correct; the effect size is wrong by 4pp.', 'loop-19', NULL, 'tradition-historical', 'researcher-blyth', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-05-real-data-generalizes', 'instrument', 'witnessed', 'Two real published studies (reintjes-2000, radelet-1981) hydrate as type-A full reversals without schema changes', 'Both studies entered via 05b-customize-data.sql. Witnessed: reintjes AllocationDistortion=0.0516, DistortionType=A; radelet AllocationDistortion=0.0684, DistortionType=A. No DAG or schema change was needed — the hydration contract generalizes.', 'loop-20b', NULL, 'tradition-epidemiology', 'researcher-greenland', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-06-policy-derivable', 'instrument', 'witnessed', 'PolicyImplication is domain-neutral: the same formula produces researcher actions across medicine, law, and education', 'All five current studies (kidney-1986, berkeley-1973, compressed-synthetic, kidney-balanced, balanced-synthetic) plus two real studies produce unambiguous PolicyImplication values from DistortionType alone. No domain-specific knowledge is encoded in the formula.', 'loop-21', NULL, 'tradition-ai-fairness', 'researcher-chouldechova', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-07-model-self-portrait', 'instrument', 'witnessed', 'ModelSummary witnesses the instrument''s own epistemic coverage as a first-class derived fact', 'ModelSummary aggregates ReversalCount, ExplainedCount, TypeA/B/C/D counts, and AvgAllocationDistortion across all studies. The model describes its own completeness in a single row.', 'loop-10', NULL, 'tradition-dag', 'researcher-spirtes-glymour-scheines', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-08-type-c-real', 'open-question', 'witnessed', 'Does the published literature contain real type-C studies (compression without sign flip)?', 'Witnessed in loop-24: hannan-1994 (CABG surgery), titanic-1912, melanoma-altman-1991, and coffee-tverdal-2020 all hydrate as DistortionType=C. AllocationDistortion>0.01, IsSignFlip=FALSE — the correct pooled direction but compressed magnitude. The type-C cell is not a synthetic pathology.', 'loop-24', 'loop-25', 'tradition-epidemiology', 'researcher-greenland', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-09-causal-vs-geometric', 'open-question', 'witnessed', 'AllocationDistortion is a geometric measure; causal interpretation requires external domain knowledge, gated by AdjustmentAppropriate', 'Berkeley has the highest AllocationDistortion (0.1934) but CausalRole=contested (mediator vs confounder), proving that geometric severity and causal confounding are not the same thing. The instrument is deliberately geometric: it classifies distortion type and flags the corrected winner from allocation arithmetic alone. Whether it is safe to act on that correction as a causal claim is answered by AdjustmentAppropriate — which gates on ConditioningRisk and CausalClaimStatus. The two layers are complementary, not competing. The instrument computes the geometry; the researcher supplies the causal account. This is a scope boundary, not a limitation.', 'loop-30', 'loop-23', 'tradition-dag', 'researcher-dong-cai-zhao', 'researcher-spirtes-glymour-scheines') ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-10-instrument-specifiable', 'methodology', 'witnessed', 'The full instrument can be specified precisely enough for any researcher to apply it to a new study', 'Witnessed in loop-26: InstrumentSpec table enumerates 5 input fields, 10 derived coordinates, 2 classification rules, and 3 adapter-requirement rows. Machine-verifiable against the full 90+ study corpus.', 'loop-26', 'loop-30', 'tradition-historical', 'researcher-blyth', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-11-reversal-recovery', 'instrument', 'witnessed', 'The model can produce the allocation-corrected winner directly from existing DAG fields — no new data required', 'CorrectedGap = WeightedStratumGapSum (already derived in loop-12/17). CorrectedWinner is a sign-read on CorrectedGap. CorrectedVsPooledAgreement is TRUE for Type-D studies and FALSE for Type-A/B studies. For kidney-1986: CorrectedGap=+0.0537, CorrectedWinner=A, CorrectedVsPooledAgreement=FALSE (pooled said B; corrected says A). The reversal recovery is free — it costs zero new data.', 'loop-27', NULL, 'tradition-dag', 'researcher-spirtes-glymour-scheines', NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-12-signal-purity-theorem', 'theorem', 'witnessed', 'SignalPurity < 0.5 is a necessary condition for allocation-driven reversal', 'Witnessed across all reversal studies (type A + B) in the 90+ study corpus: every study with AllocationDirection=''reversal'' has SignalPurity < 0.5. The algebraic proof: reversal requires SignedPooledGap and CorrectedGap to have opposite signs, which requires AllocationDistortion > |CorrectedGap|, which is exactly SignalPurity < 0.5. inv-signal-purity-sign-flip enforces this as a DAG invariant. AvgSignalPurityReversal ≈ 0.35 vs AvgSignalPurityNonReversal ≈ 0.65 — gap of ~0.30.', 'loop-44', 'loop-44', 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-13-cplus-cminus-opposite-errors', 'taxonomy', 'witnessed', 'C+ (amplification) and C- (compression) are epistemically opposite errors with opposite clinical implications', 'titanic-1912 (C+, DistortionRatio=1.359): allocation inflates first-class survival advantage from 27.5pp corrected to 37.4pp pooled — overconfidence. melanoma-altman-1991 (C+, DistortionRatio=2.087): allocation doubles apparent female survival advantage — severe overconfidence. hannan-1994 (C-, DistortionRatio=0.314): allocation compresses CABG advantage from 8.9pp corrected to 2.8pp pooled — underconfidence, risk of premature treatment abandonment. The prior type-C category hid this distinction. Now separated by DistortionRatio > 1 (C+) vs DistortionRatio ∈ (0,1) (C-).', 'loop-43', 'loop-43', 'tradition-epidemiology', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-14-scale-is-discovery-path', 'methodology', 'witnessed', 'Cross-domain SignalPurity correlations require a pre-registered unbiased corpus of 50+ studies to distinguish pattern from selection artifact', 'Partial domain patterns witnessed across 90+ studies (loop-61): epidemiology avg distortion 0.050 vs education 0.004; legal/sports/epidemiology flip rates ~27% vs economics 0%. Full causal domain→DistortionType mapping still requires pre-registered expansion beyond convenience sample, but the instrument now supports DiscoveryHypotheses/Findings for ongoing corpus-scale tests.', 'loop-61', '', NULL, NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-15-latent-flip-potential', 'instrument', 'witnessed', 'Type-D at observed allocation does not imply allocation-stable — 70% of SAFE studies flip under counterfactual reweighting', 'LatentTypeDCount=45, TypeDCount=64, LatentTypeDFraction=0.703. LatentFlipPotential=TRUE when DistortionType=D AND PooledGapCrossesZero=TRUE. Examples: uc-systemwide-admissions (Type D, sweep range 0.56), recsys-offline-eval (Type D, sweep range 0.56). The ScreeningTier SAFE label describes observed allocation only; sweep reveals latent flip potential.', 'loop-61', NULL, 'tradition-historical', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-16-small-effect-fragile', 'instrument', 'witnessed', 'In this corpus, allocation-stable Type-D rows carry larger observed pooled gaps than latent Type-D rows', 'AvgPooledGapStableD=0.102 across 19 stable Type-D studies; AvgPooledGapLatentD=0.022 across 45 latent Type-D studies. Stable studies also have lower sweep range (avg 0.072 vs 0.211). Corpus-descriptive pattern on loop-61 convenience sample — not a deductive law. Small observed effects tend to be allocation-fragile even when currently classified SAFE.', 'loop-61', NULL, 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-17-economics-flip-free', 'corpus-pattern-superseded', 'historical', 'Economics-domain 2×K encodings in this corpus produce zero sign-flips — composition studies read as Type D or C−', 'EconomicsSignFlipCount=0 across 8 economics studies (6 Type D, 2 Type C−). Contrast epidemiology (6 sign-flips / 22 studies, 27.3%). Composition and wage-decomposition paradoxes compress or stabilize rather than flip in this instrument''s 2×K encoding. **Superseded at loop-78 (N=238):** EconomicsSignFlipCount=10 (25.6% flip rate) after expansion wave 3 bulk encode — pattern was corpus-contingent on pre-expansion selection, not a domain law.', 'loop-61', NULL, 'tradition-epidemiology', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-18-causal-role-flip-mode', 'instrument', 'witnessed', 'Causal role predicts manifest vs latent reversal mode — confounders flip at observed allocation; collider/selection flips stay sweep-latent', 'Loop-62 research sweep: H-causal-manifest PASS (confFlip=15 vs collManifest=0). H-causal-latent PASS (collManifest=0, collLatent=5, collN=7). Confounder Type-D rows often show latent-only sweep sensitivity (45 latent-only) without manifest sign-flip — the mechanism split is about reversal mode when sign-flips occur, not absence of sweep fragility. Existing LatentFlipPotential + StratumCausalRole suffice; defer ManifestReversal first-class fields to loop-67+.', 'loop-62', NULL, 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-19-explained-tracks-confounding', 'instrument', 'witnessed', 'IsParadoxExplained tracks adjust-resolvable confounding, not geometric distortion', 'In this corpus, IsParadoxExplained=TRUE iff the study has a manifest sign-flip driven by a confounder — i.e. stratification resolves the reversal. It is FALSE for all C+/C−/D types, and FALSE for the three contested/mediator sign-flips (berkeley-1973, berkeley-six-dept-1973, birth-weight-paradox). The boundary separates ''stratify immediately'' from ''do not naively adjust for a collider or mediator''.', 'loop-63', NULL, 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-20-signal-purity-ceiling', 'theorem', 'witnessed', 'SignalPurity < 0.5 is a build-breaking invariant for sign-flip studies — witnessed at corpus scale', 'At 96-study corpus scale, every manifest sign-flip has SignalPurity strictly below 0.5 (corpus max: 0.483, jeter-justice-1997). The melanoma-altman-1991 boundary case (purity=0.479, C+, pooled gap crosses zero, no flip) confirms the law is tight but not violated. This graduates from corpus hypothesis (loop-61) to build-breaking invariant: any future study encoding that produces a sign-flip with purity >= 0.5 is an encoding error, not a counterexample.', 'loop-64', NULL, 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-21-catalog-tags-not-predictors', 'methodology', 'witnessed', 'Catalog ExpectedDistortionType tags are mechanism priors, not taxonomy predictors — exact match rate 19.4%', 'Loop-65 audit: 18/93 exact matches (19.4%), 75 mismatches. Sign-flip prediction 18/71 (25.4%). Biggest bucket Expected A→observed D (23 studies). Both H-catalog hypotheses PASS (<50%). Defer ExpectedSignFlip vs ExpectedDistortionType split to loop-67+.', 'loop-65', NULL, 'tradition-epidemiology', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-22-domain-flip-geometry', 'corpus-pattern-superseded', 'historical', 'Domain flip-rate heterogeneity survives max_stratum_imbalance conditioning — economics 0%, epi/legal/sports ~27%', 'Loop-66: H-domain-flip-geometry-controlled PASS. economics_high_imbalance_sign_flip_count=0; epidemiology_high_imbalance_sign_flip_rate=0.273; legal=0.286; sports=0.273. Pattern survives geometry control — not purely catalog selection artifact. **Superseded at loop-78 (N=238):** econHighImbFlips=10; all domains elevated (epi=65%, legal=57%, sports=60%) — geometry-controlled domain gap collapsed after wave-3 encode.', 'loop-66', NULL, 'tradition-historical', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-23-research-sweep-synthesis', 'methodology', 'witnessed', 'Research sweep loops 62–66: confirmed laws vs corpus patterns vs deferred vocabulary', 'Laws (build-breaking): SignalPurity<0.5 for sign-flips (loop-64), IsParadoxExplained↔confounder (loop-63). Corpus patterns: causal-role reversal mode (loop-62), latent Type-D 70% (loop-61), catalog tag falsification 19% exact (loop-65), domain gap survives geometry control (loop-66). Deferred loop-67+: ManifestReversal/LatentReversal fields, ExpectedSignFlip catalog split, Discovery UI polish. inv-discovery-all-confirmed: 11/11 PASS.', 'loop-66', NULL, 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-24-collider-no-manifest-v2', 'instrument', 'witnessed', 'Collider/selection studies produce zero manifest sign-flips at observed allocation — theorem candidacy', 'Loop-69: H-collider-no-manifest-v2 PASS. ColliderSelectionManifestCount=0 including hernandez-diaz birth-weight collider (Expected-A catalog tag, observed Type D). Catalog Expected-A does not predict collider geometry.', 'loop-69', NULL, 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-25-cplus-magnitude-blindspot', 'instrument', 'witnessed', 'Type-C+ carries the largest mean AllocationDistortion — invisible to is_sign_flip screens', 'Loop-69: H-cplus-magnitude PASS. CPlusAvgDistortion > CMinusAvgDistortion and > TypeDAvgDistortion. Magnitude inflation is the largest quantitative error class among non-flip distortions.', 'loop-69', NULL, 'tradition-epidemiology', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-26-sweep-fragile-class', 'instrument', 'witnessed', 'Sweep-fragile Type-D class: pooled-safe studies with wide counterfactual wander (≥4 in corpus)', 'Loop-69: H-ultra-fragile PASS. SweepFragileCount>=4 — Type-D rows with signal_purity=1, allocation_distortion=0, sweep_pooled_gap_range>0.3, allocation_fragility>=10. Invisible to pooled-only screens.', 'loop-69', NULL, 'tradition-historical', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-27-economics-encoding-selection', 'corpus-pattern-superseded', 'historical', 'Economics Expected-A catalog tags mismatch observed Type D at 2×K encoding — selection not immunity', 'Loop-69: H-econ-encoding-selection PASS. EconomicsExpectedAMismatchRate=1.0 on expansion-wave-1 Expected-A batch (5/5 Type D). Economics zero-flip reflects encoding limits and catalog priors, not domain paradox immunity. **Superseded at loop-78 (N=238):** EconomicsExpectedAMismatchRate=0.50 after wave-3 dilution — half of Expected-A economics rows now match; pattern sharpened not falsified but no longer unanimous.', 'loop-69', NULL, 'tradition-historical', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-28-corrected-gap-invariance-theorem', 'theorem', 'witnessed', 'CorrectedGap (= WeightedStratumGapSum) is invariant under allocation reweighting — the conserved quantity', 'Loop-73: inv-corrected-gap-invariant PASS 238/238; MaxStudySweepCorrectedGapRange=0; CorrectedGapInvariantFailCount=0. CorrectedGap (=WeightedStratumGapSum) invariant under allocation reweighting across full corpus including expansion wave 3.', 'loop-73', 'loop-73', 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-29-explained-confounder-theorem', 'theorem', 'witnessed', 'IsParadoxExplained ⟺ confounder manifest sign-flip — adjust-resolvable confounding is the unique explanation condition', 'Loop-74: H-explained-bidirectional PASS. ExplainedConfounderCount=ConfounderSignFlipCount; FalsePositiveExplainedCount=0; UnexplainedConfounderSignFlipCount=0. inv-explained-sign-flip-confounder + inv-confounder-signflip-explained both PASS.', 'loop-74', 'loop-74', 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-30-collider-no-manifest-theorem', 'theorem', 'witnessed', 'Given correct causal-role annotation, collider/selection studies produce no manifest sign-flips at observed allocation', 'Loop-75: ColliderSelectionCount>=10 with ColliderSelectionManifestCount=0 after encoding heckman-1979 + hoxby-murarka-2009 and re-tagging simonsen/hammond to selection; fryer-2016 reclassified contested. inv-collider-no-manifest PASS.', 'loop-75', 'loop-75', 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-31-theorem-portfolio-synthesis', 'methodology', 'witnessed', 'Four witnessed theorems: SignalPurity, CorrectedGap invariance, Explained↔Confounder, Collider-no-manifest — plus corpus patterns that remain non-theorems', 'Loop-76: TheoremCount>=4 (conc-12/20 SignalPurity + conc-28/29/30). All loops 61-75 discovery hypotheses PASS. Methods-export ready. **Loop-78 update:** six corpus patterns superseded at N=238; theorems and build-breaking invariants unchanged — see conc-32.', 'loop-76', 'loop-76', 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-expansion-wave-synthesis', 'methodology', 'witnessed', 'Expansion waves 1–2 (loops 68–72): adversarial stress tests survived; theorem candidacy patterns held or sharpened', 'Pending loop-72 LoopReview. Witnesses collider-no-manifest, economics encoding selection, sweep-fragile class, domain profile stability at N>110.', 'loop-76', 'loop-72', 'tradition-historical', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-32-expansion-wave-3-supersession', 'methodology', 'witnessed', 'Expansion wave 3 (loop-77→78): six corpus patterns superseded at N=238 — theorems and invariants hold', 'Loop-78 LoopReview at 238 studies (233 real). Six EpistemicTier=corpus-pattern-superseded hypotheses witnessed FAIL: H-econ-zero (flips=10), H-domain-dist (epi<edu), H-catalog-flip-prediction (flipPred=54.1%), H-domain-flip-geometry-controlled (econHighImbFlips=10), H-econ-encoding-selection (mismatch=50%), H-domain-profiles-stable (econFlipRate=25.6%). H-catalog-exact-match still PASS (39.1%). Five theorems + all critical invariants unchanged. Corpus patterns are scale- and selection-contingent; laws are not.', 'loop-78', NULL, 'tradition-epidemiology', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-33-confounder-identity-layer', 'instrument', 'witnessed', 'ConfounderIdentity ontology: cross-study accountable stratum archetypes (loop-80)', 'Loop-81 witness at N=238: 15 identities, 233/233 real stratum variables mapped (100% coverage). H-age-identity-flip-rate PASS (48.6% manifest, n=35). H-severity-vs-age-latent FAIL globally (0.917 > 0.813) — domain modulation deferred to loop-82 IdentityDomainCells.', 'loop-81', NULL, 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-34-latent-predominant-family', 'theorem', 'candidate', 'Latent-predominant mechanism family: selection-frailty, collider-proxy, and geographic-composition produce near-zero manifest flips', 'Loop-84: H-selection-frailty-zero-manifest, H-collider-identity-low-manifest, H-geographic-stable-type-d all PASS. These three identities form a coherent latent-predominant cluster distinct from manifest-flip-prone identities (age-composition 48.6%, severity-in-medicine ≥45%). Candidate for theorem promotion pending loop-96 invariant tightening.', 'loop-84', 'loop-84', 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

INSERT INTO conclusions (conclusion_id, category, status, title, evidence, witnessed_in_loop, target_loop, tradition_id, researcher_id, challenges_researcher)
VALUES ('conc-35-unexplained-identity-sink-theorem', 'theorem', 'witnessed', 'Identity-conditioned explained theorem: all unexplained sign-flips confined to contested-org-choice and collider-proxy identities', 'Loop-85 at N=238: H-unexplained-flips-only-nonconfounders PASS. UnexplainedConfounderSignFlipCount=0. The three unexplained flips (conc-29 exception list) map exclusively to id-contested-org-choice (2) and id-collider-proxy (1). This extends the loop-74 biconditional (conc-29): explained↔confounder holds for every unambiguous confounder identity; violations are confined to ontologically ambiguous categories. inv-unexplained-identity-sink: PASS (critical, 30 total invariants).', 'loop-85', 'loop-85', 'tradition-dag', NULL, NULL) ON CONFLICT (conclusion_id) DO UPDATE SET category = EXCLUDED.category, status = EXCLUDED.status, title = EXCLUDED.title, evidence = EXCLUDED.evidence, witnessed_in_loop = EXCLUDED.witnessed_in_loop, target_loop = EXCLUDED.target_loop, tradition_id = EXCLUDED.tradition_id, researcher_id = EXCLUDED.researcher_id, challenges_researcher = EXCLUDED.challenges_researcher;

-- ----------------------------------------------------------------------------
-- UIScreens: Table: UIScreens — the canonical screens that comprise the Simpson's Paradox Explorer UI. Each row defines one screen: its purpose, its primary data source (which rulebook view it reads), and the user action it supports. A developer can reconstruct the full UI from this table without any prior knowledge of the application.
-- ----------------------------------------------------------------------------
INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-01-study-list', 'Study List', '/', 'Studies', 'Show all studies with their DistortionType badge and AllocationDistortion magnitude so a user can immediately see which studies exhibit the paradox and how severely.', 'Title, DistortionType (from TreatmentRankings), AllocationDistortion, PolicyImplication, IsSignFlip, TotalCases', 'Click a study row to navigate to the Study Detail screen.', 'tradition-historical', 'conc-05-real-data-generalizes') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-02-study-detail', 'Study Detail', '/study/:studyId', 'TreatmentRankings', 'Show one study''s complete geometry: pooled rates, per-stratum rates, allocation fractions, AllocationDistortion, DistortionType, and PolicyImplication — the full causal picture for this study.', 'PooledRateA, PooledRateB, PooledWinner, PerStratumWinner, IsReversal, IsSignFlip, WeightedStratumGapSum, SignedPooledGap, AllocationDistortion, DistortionType, PolicyImplication, ConfoundersInStudy, IsParadoxExplained', 'Expand strata panel to see per-stratum breakdown; navigate to Strata Detail.', 'tradition-historical', 'conc-01-paradox-is-derived') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-03-strata-detail', 'Strata Detail', '/study/:studyId/strata', 'StratumSummaries', 'Show every (stratum, treatment) cell for a study: StratumSuccessRate, AllocationBias, StratumGap, WeightedStratumGap — the leaf-level evidence for why the pooled conclusion is or isn''t misleading.', 'StratumLabel, TreatmentLabel, StratumSuccessRate, StratumRateA, StratumRateB, StratumWinner, AllocationBias, AllocationFractionA, AllocationFractionB, StratumGap, WeightedStratumGap, StratumFraction', 'Hover a cell for the raw Successes/Cases count from CaseCells.', 'tradition-epidemiology', 'conc-02-reversal-from-allocation') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-04-confounder-panel', 'Confounder Panel', '/study/:studyId/confounder', 'StratumVariables', 'Show the stratifying variable''s causal role for a study: VariableName, CausalRole, AffectsTreatmentAssignment, AffectsOutcome, IsConfounder, MechanismNote.', 'VariableName, CausalRole, AffectsTreatmentAssignment, AffectsOutcome, IsConfounder, MechanismNote', 'Read the mechanism note; understand why IsParadoxExplained is TRUE or FALSE for this study.', 'tradition-dag', 'conc-09-causal-vs-geometric') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-05-distortion-plane', 'Distortion Plane', '/plane', 'TreatmentRankings', 'Plot all studies on a 2D plane: AllocationDistortion (x-axis) × ReversalIntensity (y-axis), colored by DistortionType. Shows the geometric taxonomy at a glance and reveals how the four types partition the plane.', 'Title (from Studies), AllocationDistortion, ReversalIntensity, IsSignFlip, DistortionType, PolicyImplication, ParadoxStrength', 'Click a data point to navigate to that study''s Study Detail screen.', 'tradition-historical', 'conc-04-type-c-exists') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-06-model-summary', 'Model Summary', '/summary', 'ModelSummary', 'Show the instrument''s self-portrait: how many studies, how many of each DistortionType, average AllocationDistortion, total paradox strength — the epistemic coverage of the full model instance.', 'StudyCount, ReversalCount, ExplainedCount, TypeACount, TypeBCount, TypeCCount, TypeDCount, AvgAllocationDistortion, TotalParadoxStrength', 'Navigate to Study List or Distortion Plane from this summary.', 'tradition-historical', 'conc-07-model-self-portrait') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-07-loop-history', 'Loop History', '/loops', 'Loops', 'Show the full build history: all 31 loops with their status, new concept, domain question, and mock data note. Lets a developer understand why the model is shaped the way it is — the DAG is the story.', 'LoopId, Title, Status, NewConcept, DomainQuestion, MockDataNote, NextSuggestion', 'Filter by Status (complete/planned); click a loop to expand its full detail.', 'tradition-historical', 'conc-10-instrument-specifiable') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-08-methodology', 'Methodology', '/methodology', 'Methodology', 'Show the ten first-principles methodological axioms that shaped this model — from CMCC as the floor, through DAG-first decomposition, to the four-type taxonomy. Enables a developer to apply the same process to a new domain.', 'Phase, Title, Statement, WhyItMatters, IllustratedByLoop', 'Click IllustratedByLoop to jump to that loop in the Loop History screen.', 'tradition-dag', 'conc-10-instrument-specifiable') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-09-conclusions', 'Conclusions', '/conclusions', 'Conclusions', 'Show all witnessed and planned conclusions, grouped by category (domain / instrument / methodology / open-question). The read-out of what this model has actually established.', 'Category, Status, Title, Evidence, WitnessedInLoop, TargetLoop', 'Filter by Status (witnessed/planned/open); click WitnessedInLoop to navigate to Loop History.', 'tradition-historical', 'conc-10-instrument-specifiable') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

INSERT INTO ui_screens (screen_id, title, route, primary_entity, purpose, key_fields, user_action, tradition_id, primary_conclusion)
VALUES ('screen-10-discovery', 'Discovery Research', '/discovery', 'DiscoveryFindings', 'Show pre-registered DiscoveryHypotheses and witnessed DiscoveryFindings — loop-61 corpus patterns and loop-62 causal-role × manifest/latent sweep with study-level breakdown by StratumCausalRole.', 'HypothesisId, HypothesisStatement, ObservedMetric, IsConfirmed, Evidence, WitnessedInLoop', 'Review PASS/FAIL cards; filter by RegisteredInLoop; drill into studies by causal role and flip mode.', 'tradition-epidemiology', 'conc-18-causal-role-flip-mode') ON CONFLICT (screen_id) DO UPDATE SET title = EXCLUDED.title, route = EXCLUDED.route, primary_entity = EXCLUDED.primary_entity, purpose = EXCLUDED.purpose, key_fields = EXCLUDED.key_fields, user_action = EXCLUDED.user_action, tradition_id = EXCLUDED.tradition_id, primary_conclusion = EXCLUDED.primary_conclusion;

-- ----------------------------------------------------------------------------
-- UIComponents: Table: UIComponents — the reusable visual building blocks used across UIScreens. Each row defines one component: what it renders, which entity it reads, and what props it requires. A developer can implement the full UI by composing these components onto the screens defined in UIScreens.
-- ----------------------------------------------------------------------------
INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-01-distortion-badge', 'DistortionBadge', 'screen-01-study-list, screen-02-study-detail, screen-05-distortion-plane', 'TreatmentRankings', 'A colored pill/chip that shows DistortionType (A/B/C/D) and PolicyImplication for one study. Color-coded: A=red (stratify-immediately), B=orange (investigate-confounder), C=yellow (check-allocation-bias), D=green (pooled-analysis-trustworthy).', 'DistortionType, PolicyImplication', 'Pill shape, 2–3 chars for the type letter, tooltip on hover showing PolicyImplication text. Consistent color across all screens.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-02-rate-comparison-bar', 'RateComparisonBar', 'screen-02-study-detail, screen-03-strata-detail', 'TreatmentRankings', 'A side-by-side horizontal bar chart comparing PooledRateA vs PooledRateB (or StratumRateA vs StratumRateB for strata). The bar for the loser under equal-weight allocation is visually distinguished from the bar for the pooled loser.', 'PooledRateA, PooledRateB, PooledWinner, WeightedStratumGapSum, SignedPooledGap, IsSignFlip', 'Two horizontal bars, labeled A and B. Arrow or bracket showing the gap. IsSignFlip=TRUE triggers a ''reversal'' annotation. Width proportional to rate (0–1 scale).') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-03-allocation-heatmap', 'AllocationHeatmap', 'screen-03-strata-detail', 'StratumSummaries', 'A grid of (Stratum × Treatment) cells where cell color encodes AllocationBias magnitude and sign. Positive bias (A over-allocated here) in one color; negative (B over-allocated) in another. Cell text shows AllocationFractionA and AllocationFractionB.', 'StratumLabel, TreatmentLabel, AllocationBias, AllocationFractionA, AllocationFractionB, StratumSuccessRate', 'Matrix layout: rows=strata, cols=treatments. Diverging color scale centered at 0. Tooltip shows raw Cases and Successes from CaseCells.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-04-distortion-plane-scatter', 'DistortionPlaneScatter', 'screen-05-distortion-plane', 'TreatmentRankings', 'A 2D scatter plot with AllocationDistortion on the x-axis and ReversalIntensity on the y-axis. Each point is one study, colored by DistortionType. Quadrant lines at AllocationDistortion=0.01 (threshold) and ReversalIntensity=1.0 (unanimity) divide the plane into the four types.', 'AllocationDistortion, ReversalIntensity, DistortionType, PolicyImplication, IsSignFlip', 'SVG or canvas scatter. Labeled quadrant regions. Clickable points. Legend showing type → color → policy action.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-05-stratum-gap-waterfall', 'StratumGapWaterfall', 'screen-03-strata-detail', 'StratumSummaries', 'A waterfall chart showing how each stratum''s WeightedStratumGap contributes to WeightedStratumGapSum, then how the allocation re-weights them to produce SignedPooledGap. The visual makes the mechanism equation explicit: pooled = Σ(weight × rate).', 'StratumLabel, StratumGap, StratumFraction, WeightedStratumGap, WeightedStratumGapSum, SignedPooledGap', 'Waterfall/stacked bar: each stratum''s WeightedStratumGap as a segment; running sum shown; final total vs actual SignedPooledGap shown side-by-side. IsSignFlip highlights the sign difference.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-06-model-summary-scorecard', 'ModelSummaryScorecard', 'screen-06-model-summary', 'ModelSummary', 'A summary scorecard showing all ModelSummary fields as labeled metric tiles: StudyCount, ReversalCount, ExplainedCount, TypeA/B/C/D counts, AvgAllocationDistortion, TotalParadoxStrength.', 'StudyCount, ReversalCount, ExplainedCount, TotalParadoxStrength, AvgParadoxStrength', 'Grid of metric tiles. Each tile: large number, small label. Color: ReversalCount in orange/red; ExplainedCount in green; TypeD in grey. Single row layout on desktop, 2-column on mobile.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-07-confounder-card', 'ConfounderCard', 'screen-04-confounder-panel', 'StratumVariables', 'A card showing one StratumVariable row: VariableName, CausalRole badge, AffectsTreatmentAssignment checkbox, AffectsOutcome checkbox, IsConfounder result, and MechanismNote prose block.', 'VariableName, CausalRole, AffectsTreatmentAssignment, AffectsOutcome, IsConfounder, MechanismNote', 'Card with header=VariableName, CausalRole as a badge (confounder=red, mediator=orange, contested=yellow, unknown=grey), two boolean indicators, and MechanismNote as body text.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-08-loop-timeline', 'LoopTimeline', 'screen-07-loop-history', 'Loops', 'A vertical timeline of all Loops rows, grouped by Status. Each entry shows LoopId, Title, Status indicator, NewConcept chip, and an expandable section with DomainQuestion, MockDataNote, and NextSuggestion.', 'LoopId, Title, Status, NewConcept, DomainQuestion, MockDataNote, NextSuggestion', 'Vertical list. Status=complete: solid circle; in-progress: half-filled; planned: open circle. Expandable accordion per entry. Color: complete=green, in-progress=blue, planned=grey.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-09-policy-action-banner', 'PolicyActionBanner', 'screen-02-study-detail', 'TreatmentRankings', 'A prominent banner at the top of the Study Detail screen showing PolicyImplication as a clear action statement, color-coded by DistortionType. Includes a one-sentence explanation of why this action follows from the geometry.', 'PolicyImplication, DistortionType, AllocationDistortion, IsSignFlip', 'Full-width colored banner. Large icon (e.g. warning triangle for A, magnifying glass for B, scale for C, checkmark for D). Bold action text. Secondary line explaining the geometric basis.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-10-conclusion-list', 'ConclusionList', 'screen-09-conclusions', 'Conclusions', 'A filterable list of Conclusions rows grouped by Category and Status. Each entry shows the Title, Status badge, Evidence summary, and a link to the WitnessedInLoop or TargetLoop.', 'Category, Status, Title, Evidence, WitnessedInLoop, TargetLoop', 'Grouped list with category headers. Status badge: witnessed=green, planned=blue, open=orange. Evidence shown as collapsed text (expand on click). Loop links navigate to LoopTimeline.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

INSERT INTO ui_components (component_id, component_name, used_on_screens, primary_entity, description, required_fields, visual_spec)
VALUES ('comp-11-discovery-panel', 'DiscoveryResearchPanel', 'screen-10-discovery', 'DiscoveryFindings', 'Grouped hypothesis cards with observed metrics, PASS/FAIL badges, and a study table filtered by StratumCausalRole × flip mode (manifest / latent-only / stable).', 'HypothesisId, HypothesisStatement, ObservedMetric, IsConfirmed, Evidence, WitnessedInLoop', 'Two sections: hypothesis cards (green PASS / red FAIL) then study table with columns Study, StratumCausalRole, IsSignFlip, PooledGapCrossesZero, IsLatentOnlyFlip, DistortionType.') ON CONFLICT (component_id) DO UPDATE SET component_name = EXCLUDED.component_name, used_on_screens = EXCLUDED.used_on_screens, primary_entity = EXCLUDED.primary_entity, description = EXCLUDED.description, required_fields = EXCLUDED.required_fields, visual_spec = EXCLUDED.visual_spec;

-- ----------------------------------------------------------------------------
-- InstrumentSpec: Table: InstrumentSpec — the complete specification of the Simpson's Paradox classification instrument. One row per component: required input fields, derived coordinates, classification outputs, and adapter requirements. Every row is machine-verifiable against the 238-study corpus. This table is the distillation of loops 1–25 into a reusable tool.
-- ----------------------------------------------------------------------------
INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('input-study', 'input', 'Study', 'string', 'CaseCells', '', 'A unique identifier for the study being classified (e.g. ''kidney-1986'').', 'Assign a slug that is stable and unique. All rows for a study share this value.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('input-stratum', 'input', 'StratumLabel', 'string', 'CaseCells', '', 'The label of the subgroup (stratum) for this cell — the variable being stratified on (e.g. ''large'', ''high-risk'', ''male'').', 'Must be consistent across the A and B cells within the same stratum. At least 2 strata required.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('input-treatment', 'input', 'TreatmentLabel', 'string', 'CaseCells', '', 'Which treatment (exposure, group, class) this cell belongs to — ''A'' or ''B''.', 'Exactly two treatment labels per study. Encode the group you want to investigate as ''A''; comparator as ''B''.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('input-successes', 'input', 'Successes', 'integer', 'CaseCells', '', 'Count of successful outcomes (survived, passed, admitted, etc.) in this cell.', 'Must be a non-negative integer ≤ Cases. Define ''success'' consistently across all cells in the study.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('input-cases', 'input', 'Cases', 'integer', 'CaseCells', '', 'Total number of observations (trials, patients, applicants, etc.) in this cell.', 'Must be a positive integer. Every (Study, Stratum, Treatment) combination must have exactly one CaseCell row.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-stratum-rate', 'derived', 'CellSuccessRate', 'decimal', 'CaseCells', '=Successes/Cases', 'The success rate for this specific treatment within this specific stratum.', 'Computed automatically. Range [0,1].') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-pooled-rate-a', 'derived', 'PooledRateA', 'decimal', 'TreatmentRankings', '=TotalSuccessesA/TotalCasesA', 'The overall (pooled, unstratified) success rate for treatment A across all strata.', 'Computed from SUMIFS across CaseCells. This is the rate a naive observer would report.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-pooled-rate-b', 'derived', 'PooledRateB', 'decimal', 'TreatmentRankings', '=TotalSuccessesB/TotalCasesB', 'The overall (pooled, unstratified) success rate for treatment B across all strata.', 'Computed from SUMIFS across CaseCells.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-signed-pooled-gap', 'derived', 'SignedPooledGap', 'decimal', 'TreatmentRankings', '=PooledRateA - PooledRateB', 'The signed difference in pooled rates (A minus B). Positive means A appears better pooled; negative means B appears better.', 'The naive result — what the unadjusted analysis reports.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-alloc-fraction-a', 'derived', 'AllocationFractionA', 'decimal', 'StratumSummaries', '=TreatmentACasesHere/TreatmentATotalCases', 'The fraction of all treatment-A cases that fall in this stratum — treatment A''s allocation weight.', 'Sums to 1.0 across strata within a study.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-stratum-gap', 'derived', 'StratumGap', 'decimal', 'StratumSummaries', '=StratumRateA - StratumRateB', 'The signed per-stratum rate difference (A minus B). The true causal signal for this stratum, free of allocation effects.', 'Computed from within-stratum aggregation of CaseCells.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-weighted-stratum-gap', 'derived', 'WeightedStratumGap', 'decimal', 'StratumSummaries', '=((AllocationFractionA + AllocationFractionB) / 2) * StratumGap', 'The stratum gap weighted by the average of A''s and B''s allocation fractions — the equal-weight contribution of this stratum.', 'Summing across strata yields WeightedStratumGapSum.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-wgs', 'derived', 'WeightedStratumGapSum', 'decimal', 'TreatmentRankings', '=SUMIFS(StratumSummaries!WeightedStratumGap, StratumSummaries!Study, Study, StratumSummaries!TreatmentLabel, TreatmentA)', 'The equal-allocation benchmark: what SignedPooledGap would be if each treatment received the same case-mix. This is the allocation-free signal.', 'Compare to SignedPooledGap to detect distortion.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-is-sign-flip', 'derived', 'IsSignFlip', 'boolean', 'TreatmentRankings', '=IF(WeightedStratumGapSum > 0, SignedPooledGap < 0, SignedPooledGap > 0)', 'TRUE when the pooled winner (SignedPooledGap) points in the opposite direction from the equal-weight per-stratum winner (WeightedStratumGapSum). This is the sign of a reversal.', 'The primary reversal detector.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('derived-allocation-distortion', 'derived', 'AllocationDistortion', 'decimal', 'TreatmentRankings', '=ABS(WeightedStratumGapSum - SignedPooledGap)', 'The absolute magnitude of the allocation distortion — how much the observed pooled gap differs from the equal-weight benchmark.', 'Zero means no allocation confounding. > 0.01 is the classification threshold for types C and D.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('class-distortion-type', 'classification', 'DistortionType', 'categorical', 'TreatmentRankings', '=IF(AND(IsSignFlip, ReversalIntensity=1), ''A'', IF(AND(IsSignFlip, ReversalIntensity<1), ''B'', IF(AND(NOT(IsSignFlip), AllocationDistortion>0.01), ''C'', ''D'')))', 'The four-type classification: A=full reversal (A wins all strata, B wins pooled); B=partial reversal (split strata, pooled contradicts weighted); C=distortion without reversal (same winner, but margin compressed or inflated by ≥1pp); D=trustworthy pooled (allocation-free or near-free).', 'Output. Read-only for the researcher.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('class-policy-implication', 'classification', 'PolicyImplication', 'string', 'TreatmentRankings', '=IF(DistortionType=''A'',''stratify-immediately'', IF(DistortionType=''B'',''investigate-confounder'', IF(DistortionType=''C'',''check-allocation-bias'',''pooled-analysis-trustworthy'')))', 'The recommended analytic action given the distortion type: A→stratify immediately (pooled is misleading); B→investigate the confounder structure; C→report allocation bias alongside pooled result; D→pooled analysis is trustworthy.', 'Output. This is the instrument''s primary policy-facing deliverable.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('adapter-stratum-seed', 'adapter-requirement', 'Strata', 'string', 'Strata', '', 'One Strata row per (study, stratum) combination, with a plain-English Description of what this subgroup represents and why it matters.', 'Required for interpretability. The DAG computes rates without it, but the explanation of the paradox requires this context.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('adapter-stratum-variable', 'adapter-requirement', 'StratumVariables', 'string', 'StratumVariables', '', 'One StratumVariables row per study naming the confounding variable, its CausalRole (confounder/mediator/contested), and a MechanismNote explaining how the allocation imbalance arises.', 'CausalRole must be one of: confounder, mediator, contested, unknown. IsConfounder is derived (confounder AND both affect-flags true).') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('adapter-stratum-summaries', 'adapter-requirement', 'StratumSummaries', 'string', 'StratumSummaries', '', 'Four StratumSummaries seed rows per study (one per stratum × treatment combination) — only StratumSummaryId, Study, StratumLabel, TreatmentLabel required; all computed fields are populated by the DAG.', 'Minimum hydration contract: provide the four raw-key fields. The re-hydrate step fills in all derived values from the views.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('theorem-signal-purity', 'theorem', 'SignalPurity', 'decimal', 'TreatmentRankings', '=ABS(CorrectedGap)/(ABS(CorrectedGap)+AllocationDistortion)', 'Theorem (loop-44): manifest sign-flip requires SignalPurity < 0.5 — allocation noise exceeds true signal.', 'Build-breaking invariant inv-sign-flip-signal-purity-max. Category=theorem in conc-12/20.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('theorem-corrected-gap-invariant', 'theorem', 'CorrectedGap', 'decimal', 'TreatmentRankings', '=WeightedStratumGapSum', 'Theorem (loop-73): CorrectedGap is invariant under allocation reweighting — conserved quantity across AllocationSweep.', 'Build-breaking invariant inv-corrected-gap-invariant. Promoted conc-28.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('theorem-explained-confounder', 'theorem', 'IsParadoxExplained', 'boolean', 'TreatmentRankings', '=IsSignFlip AND StratumCausalRole=''confounder''', 'Theorem (loop-74): IsParadoxExplained ⟺ confounder manifest sign-flip — adjust-resolvable confounding is the unique explanation.', 'Biconditional: inv-explained-sign-flip-confounder + inv-confounder-signflip-explained. Promoted conc-29.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

INSERT INTO instrument_spec (spec_id, component_type, field_name, data_type, source_table, formula, natural_language, adapter_note)
VALUES ('theorem-collider-no-manifest', 'theorem', 'IsSignFlip', 'boolean', 'TreatmentRankings', '=FALSE when StratumCausalRole IN (collider, selection)', 'Theorem (loop-75, conditional): given correct causal-role annotation, collider/selection studies produce no manifest sign-flips at observed allocation.', 'Build-breaking invariant inv-collider-no-manifest. Promoted conc-30.') ON CONFLICT (spec_id) DO UPDATE SET component_type = EXCLUDED.component_type, field_name = EXCLUDED.field_name, data_type = EXCLUDED.data_type, source_table = EXCLUDED.source_table, formula = EXCLUDED.formula, natural_language = EXCLUDED.natural_language, adapter_note = EXCLUDED.adapter_note;

