-- ----------------------------------------------------------------------------
-- DiscoveryHypotheses: Table: DiscoveryHypotheses — pre-registered empirical claims tested against the corpus at loop-61. Each row states an expected pattern before querying the DAG.
-- ----------------------------------------------------------------------------
INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-latent-d', 'More than half of Type-D (SAFE) studies would flip their pooled winner under counterfactual allocation reweighting.', 'LatentTypeDFraction > 0.5', 'loop-61', 'tradition-historical', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-purity', 'Every sign-flip study has SignalPurity strictly below 0.5.', 'SignFlipSignalPurityMax < 0.5', 'loop-61', 'tradition-dag', 'consistency-check') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-small-effect', 'Allocation-stable Type-D studies carry larger observed pooled gaps than latent Type-D studies.', 'AvgPooledGapStableD > AvgPooledGapLatentD', 'loop-61', 'tradition-epidemiology', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-causal-manifest', 'Confounder-labeled studies produce manifest sign-flips at observed allocation (IsSignFlip=TRUE) far more often than collider/selection studies — reversal mode differs by mechanism class.', 'ConfounderSignFlipCount > ColliderSelectionManifestCount AND ConfounderSignFlipCount >= 10', 'loop-62', 'tradition-dag', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-causal-latent', 'Collider/selection studies produce latent-only flips under allocation sweep without manifest sign-flips at observed allocation.', 'ColliderSelectionManifestCount = 0 AND ColliderSelectionLatentOnlyCount >= 5', 'loop-62', 'tradition-epidemiology', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-explained-confounder', 'IsParadoxExplained is TRUE for all and only confounder sign-flip studies — adjust-resolvable confounding is the unique condition that makes a reversal fully explained.', 'ExplainedConfounderCount = SignFlipCount AND ExplainedNonConfounderCount = 0', 'loop-63', 'tradition-dag', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-unexplained-nonconfounder', 'Studies with IsSignFlip=TRUE and CausalRole != confounder (contested or mediator) have IsParadoxExplained=FALSE.', 'ContestedOrMediatorExplainedCount = 0', 'loop-63', 'tradition-dag', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-catalog-exact-match', 'Catalog ExpectedDistortionType exact-match rate is below 50% — curator tags behave as mechanism priors, not taxonomy predictors.', 'TypePredictionMatchRate < 0.5', 'loop-65', 'tradition-epidemiology', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-collider-no-manifest-v2', 'Collider and selection studies produce zero manifest sign-flips (DistortionType A or B) at observed allocation — including hernandez-diaz birth-weight collider tagged Expected A in catalog.', 'ColliderSelectionManifestCount = 0', 'loop-68', 'tradition-dag', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-cplus-magnitude', 'C+ studies carry higher mean AllocationDistortion than C- studies and Type-D studies — magnitude inflation is the largest quantitative error class and invisible to is_sign_flip.', 'CPlusAvgDistortion > CMinusAvgDistortion AND CPlusAvgDistortion > TypeDAvgDistortion', 'loop-68', 'tradition-epidemiology', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-ultra-fragile', 'At least four Type-D studies are sweep-fragile: signal_purity=1, allocation_distortion=0, sweep_pooled_gap_range>0.3, allocation_fragility>=10 — perfectly safe by pooled metrics yet latent-flip under reweighting.', 'SweepFragileCount >= 4', 'loop-68', 'tradition-historical', 'corpus-hypothesis') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-corrected-gap-invariant', 'CorrectedGap is allocation-invariant for every study: MAX(SweepStudySummary.SweepCorrectedGapRange) < 0.0001 and zero failing studies.', 'MaxStudySweepCorrectedGapRange < 0.0001 AND CorrectedGapInvariantFailCount = 0', 'loop-73', 'tradition-dag', 'consistency-check') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-explained-bidirectional', 'IsParadoxExplained ⟺ confounder manifest sign-flip: ExplainedConfounderCount = ConfounderSignFlipCount, no false-positive explained rows, no unexplained confounder sign-flips.', 'ExplainedConfounderCount = ConfounderSignFlipCount AND FalsePositiveExplainedCount = 0 AND UnexplainedConfounderSignFlipCount = 0', 'loop-74', 'tradition-dag', 'consistency-check') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
VALUES ('H-collider-no-manifest-theorem', 'At scale (≥10 collider/selection studies post expansion), zero manifest sign-flips: ColliderSelectionManifestCount = 0.', 'ColliderSelectionManifestCount = 0 AND ColliderSelectionCount >= 10', 'loop-75', 'tradition-dag', 'consistency-check') ON CONFLICT (hypothesis_id) DO UPDATE SET statement = EXCLUDED.statement, expected_outcome = EXCLUDED.expected_outcome, registered_in_loop = EXCLUDED.registered_in_loop, tradition_id = EXCLUDED.tradition_id, epistemic_tier = EXCLUDED.epistemic_tier;

INSERT INTO discovery_hypotheses (hypothesis_id, statement, expected_outcome, registered_in_loop, tradition_id, epistemic_tier)
